// parágrafos), correctIndex 0-3, banca "PSU-MG", cycle "Ciclo Clínico" fixo, vinhetas densas no
// estilo Medway com sinais vitais e exames laboratoriais detalhados, frequentemente terminando em
// "Assinale a alternativa CORRETA/ERRADA/INADEQUADA". Sem "Clínica Médica" como categoria genérica
// (dividida em subespecialidades, como no arquivo real). Campo `explanation` incluído a pedido do
// usuário, justificando a alternativa correta e por que cada alternativa errada está incorreta.
export const PSUMG_GERADO_2026_QUESTIONS: any[] = [
  { id: "psumg_gerado26_001", banca: "PSU-MG", cycle: "Ciclo Clínico", subject: "Ginecologia e Obstetrícia", text: "Mulher de 29 anos, G2P1, 32 semanas, vai ao Pronto Socorro com cefaleia occipital e escotomas cintilantes há 6 horas. PA 168/108mmHg, FC 92bpm. Reflexos patelares exaltados com clônus. Proteinúria de 24h: 3,8g. Plaquetas 210.000/mm³; TGO 32U/L; TGP 28U/L; creatinina 0,7mg/dL. Assinale a conduta MAIS ADEQUADA:", options: ["Iniciar sulfato de magnésio e nifedipina, com avaliação para resolução da gestação", "Iniciar apenas metildopa oral ambulatorial, sem sulfato de magnésio", "Solicitar tomografia de crânio antes de qualquer medicação", "Aguardar 48 horas de observação antes de qualquer conduta"], correctIndex: 0, explanation: "Sintomas premonitórios (cefaleia, escotomas) com hipertensão grave e proteinúria maciça caracterizam pré-eclâmpsia grave, exigindo sulfato de magnésio para prevenção de convulsões, anti-hipertensivo e avaliação para resolução da gestação. Metildopa oral ambulatorial isolada é insuficiente diante da gravidade e dos sinais premonitórios; tomografia de crânio não deve atrasar o tratamento de uma emergência hipertensiva já caracterizada clinicamente; aguardar 48 horas de observação é perigoso diante de sinais de iminência de eclâmpsia." },
  { id: "psumg_gerado26_002", banca: "PSU-MG", cycle: "Ciclo Clínico", subject: "Ginecologia e Obstetrícia", text: "Considerando a mesma paciente de 29 anos com pré-eclâmpsia grave, após estabilização inicial, evolui em 6 horas com dor súbita em hipocôndrio direito, hipotensão e sangramento vaginal escasso, cardiotocografia com bradicardia fetal sustentada. Assinale o diagnóstico MAIS PROVÁVEL:", options: ["Descolamento prematuro de placenta", "Placenta prévia", "Rotura uterina espontânea", "Corioamnionite"], correctIndex: 0, explanation: "Dor súbita, hipotensão, sangramento e sofrimento fetal agudo em gestante hipertensa são clássicos de descolamento prematuro de placenta. Placenta prévia cursaria com sangramento indolor sem hipertonia; rotura uterina espontânea é rara sem cicatriz uterina prévia; corioamnionite cursaria com febre materna, não com esse quadro agudo de dor e sofrimento fetal." },
  { id: "psumg_gerado26_003", banca: "PSU-MG", cycle: "Ciclo Clínico", subject: "Ginecologia e Obstetrícia", text: "Mulher de 33 anos, 38 semanas, em trabalho de parto, cardiotocografia evidenciando desacelerações variáveis recorrentes coincidindo com as contrações, com boa variabilidade basal entre elas. Assinale a interpretação MAIS ADEQUADA e a conduta:", options: ["Compressão de cordão umbilical; reposicionamento materno e reavaliação", "Insuficiência uteroplacentária grave; cesariana de urgência imediata", "Padrão normal sem necessidade de qualquer conduta", "Taquissistolia uterina isolada; suspensão de ocitocina, independente do padrão fetal"], correctIndex: 0, explanation: "Desacelerações variáveis coincidindo com contrações, com boa variabilidade basal preservada, sugerem compressão de cordão, geralmente manejada com reposicionamento materno e reavaliação. Cesariana de urgência imediata é desproporcional diante de variabilidade preservada, sinal tranquilizador; não é padrão normal isento de qualquer conduta, merecendo reposicionamento; taquissistolia é achado distinto relacionado ao padrão de contrações, não à descrição do caso." },
  { id: "psumg_gerado26_004", banca: "PSU-MG", cycle: "Ciclo Clínico", subject: "Ginecologia e Obstetrícia", text: "Mulher de 24 anos, primigesta, 8 semanas por DUM, vai à consulta com náuseas e vômitos intensos, incapacidade de reter líquidos, perda de 4kg. FC 108bpm, mucosas secas. Sódio 132mEq/L; potássio 3,1mEq/L; cetonúria 3+. Assinale a conduta inicial MAIS ADEQUADA:", options: ["Internação para hidratação venosa, reposição de eletrólitos e antiemético IV", "Orientação dietética isolada, com retorno ambulatorial em 2 semanas", "Antiemético oral isolado, sem necessidade de internação ou hidratação venosa", "Interrupção da gestação, dada a gravidade dos sintomas"], correctIndex: 0, explanation: "Hiperêmese gravídica com desidratação, distúrbio eletrolítico e cetonúria exige internação para hidratação venosa, reposição de eletrólitos e antiemético parenteral. Orientação dietética isolada é insuficiente diante da gravidade e da incapacidade de reter líquidos; antiemético oral isolado não corrige a desidratação e o distúrbio eletrolítico já estabelecidos; a interrupção da gestação não é indicada nesse contexto, que é tratável clinicamente." },
  { id: "psumg_gerado26_005", banca: "PSU-MG", cycle: "Ciclo Clínico", subject: "Ginecologia e Obstetrícia", text: "Mulher de 30 anos, 10 semanas, Rh negativo, parceiro Rh positivo, Coombs indireto negativo, sofre queda com trauma abdominal leve. Assinale a conduta MAIS ADEQUADA em relação à profilaxia da aloimunização Rh:", options: ["Administrar imunoglobulina anti-D", "Não administrar profilaxia, pois o Coombs indireto é negativo", "Aguardar positivação do Coombs indireto antes de qualquer conduta", "Solicitar apenas ultrassonografia obstétrica, sem profilaxia"], correctIndex: 0, explanation: "Evento sensibilizante (trauma abdominal) em gestante Rh negativo não sensibilizada indica administração de imunoglobulina anti-D, independentemente do Coombs indireto negativo prévio. Não administrar profilaxia expõe a paciente ao risco de sensibilização; aguardar positivação do Coombs contraria o próprio objetivo profilático de prevenir a sensibilização antes que ocorra; ultrassonografia isolada não substitui a profilaxia indicada." },
  { id: "psumg_gerado26_006", banca: "PSU-MG", cycle: "Ciclo Clínico", subject: "Ginecologia e Obstetrícia", text: "Mulher de 27 anos, nulípara, com dismenorreia progressiva, dispareunia de profundidade e infertilidade há 18 meses, ressonância evidenciando endometrioma ovariano bilateral de 4cm. Assinale a alternativa CORRETA sobre o manejo inicial:", options: ["Considerar tratamento cirúrgico conservador (cistectomia) associado a discussão sobre técnicas de reprodução assistida", "Histerectomia total com anexectomia bilateral como única opção terapêutica", "Observação isolada por 5 anos, sem qualquer intervenção, dado o desejo reprodutivo", "Quimioterapia sistêmica, considerando o endometrioma equivalente a neoplasia maligna"], correctIndex: 0, explanation: "Endometrioma bilateral com infertilidade pode ser conduzido com cistectomia conservadora, preservando o potencial reprodutivo, associada à discussão sobre técnicas de reprodução assistida conforme o caso. Histerectomia com anexectomia bilateral eliminaria a fertilidade, contrariando o desejo reprodutivo relatado; observar por 5 anos sem intervenção atrasa desnecessariamente o tratamento da infertilidade; endometrioma é lesão benigna, não exigindo quimioterapia." },
  { id: "psumg_gerado26_007", banca: "PSU-MG", cycle: "Ciclo Clínico", subject: "Ginecologia e Obstetrícia", text: "Mulher de 26 anos, com ciclos irregulares, hirsutismo e acne, IMC 31, ultrassonografia com ovários de volume aumentado e múltiplos folículos periféricos. Testosterona total 78ng/dL (referência até 60); TSH e prolactina normais. Assinale o diagnóstico MAIS PROVÁVEL:", options: ["Síndrome dos ovários policísticos", "Hiperplasia adrenal congênita de início tardio isolada, sem outra investigação necessária", "Tumor ovariano produtor de androgênios", "Síndrome de Cushing"], correctIndex: 0, explanation: "Oligoanovulação, hiperandrogenismo clínico e laboratorial e morfologia ovariana policística, após TSH e prolactina normais, preenchem os critérios de Rotterdam para síndrome dos ovários policísticos. A hiperplasia adrenal congênita de início tardio é diagnóstico diferencial que exigiria dosagem de 17-OH-progesterona antes de ser descartada, não uma afirmação sem investigação adicional; tumor ovariano produtor de androgênios cursaria com virilização mais abrupta e testosterona muito mais elevada; síndrome de Cushing teria outros estigmas clínicos (fácies, estrias) não descritos no caso." },
  { id: "psumg_gerado26_008", banca: "PSU-MG", cycle: "Ciclo Clínico", subject: "Ginecologia e Obstetrícia", text: "Mulher de 48 anos, com sangramento uterino aumentado e prolongado há 4 meses, biópsia de endométrio confirmando hiperplasia endometrial sem atipia, sem desejo reprodutivo. Assinale a conduta terapêutica de PRIMEIRA LINHA:", options: ["Dispositivo intrauterino liberador de levonorgestrel ou progestagênio oral", "Histerectomia total, independente de tratamento hormonal prévio", "Radioterapia pélvica isolada", "Observação isolada, sem qualquer tratamento"], correctIndex: 0, explanation: "A hiperplasia endometrial sem atipia é tratada em primeira linha com progestagênio (DIU de levonorgestrel ou via oral), com reavaliação histológica. Histerectomia não é a primeira linha para hiperplasia sem atipia; radioterapia não é tratamento indicado para essa condição benigna; observação isolada ignora o risco de progressão, ainda que menor na ausência de atipia." },
  { id: "psumg_gerado26_009", banca: "PSU-MG", cycle: "Ciclo Clínico", subject: "Ginecologia e Obstetrícia", text: "Mulher de 35 anos, puérpera de 10 dias, com febre de 38,9°C, mama esquerda hiperemiada e dolorosa em quadrante superior externo, área de flutuação de 3cm à palpação. Assinale a conduta MAIS ADEQUADA:", options: ["Drenagem cirúrgica (ou punção guiada) associada a antibioticoterapia", "Antibioticoterapia isolada, sem qualquer drenagem", "Suspensão definitiva do aleitamento materno como única conduta", "Apenas anti-inflamatório, sem antibioticoterapia ou drenagem"], correctIndex: 0, explanation: "Área de flutuação indica abscesso mamário já formado, exigindo drenagem (cirúrgica ou por punção guiada) associada à antibioticoterapia. Antibioticoterapia isolada é insuficiente diante de coleção purulenta já organizada; suspender definitivamente o aleitamento não é a conduta padrão, podendo ser mantido na mama não afetada conforme orientação; anti-inflamatório isolado não trata a infecção nem o abscesso já formado." },
  { id: "psumg_gerado26_010", banca: "PSU-MG", cycle: "Ciclo Clínico", subject: "Ginecologia e Obstetrícia", text: "Mulher de 41 anos, com sangramento pós-coital recorrente há 3 meses, exame especular evidenciando lesão exofítica e friável no colo uterino, sangrante ao toque. Assinale a conduta MAIS ADEQUADA:", options: ["Biópsia dirigida da lesão", "Citologia oncótica isolada, sem biópsia da lesão visível", "Tratamento empírico com antibiótico vaginal, sem biópsia", "Observação clínica por 6 meses, sem qualquer investigação"], correctIndex: 0, explanation: "Lesão exofítica e friável visível ao exame especular, com sangramento ao toque, exige biópsia dirigida para diagnóstico histológico, independentemente do resultado citológico. Citologia isolada, sem biópsia de lesão macroscopicamente visível e suspeita, pode subestimar uma neoplasia já estabelecida; tratamento empírico com antibiótico não se justifica sem diagnóstico definido; observar por 6 meses atrasa perigosamente o diagnóstico de uma possível neoplasia cervical." },
  { id: "psumg_gerado26_011", banca: "PSU-MG", cycle: "Ciclo Clínico", subject: "Ginecologia e Obstetrícia", text: "Gestante de 36 semanas, com hipertensão gestacional em acompanhamento, evolui com dor em hipocôndrio direito e cefaleia, exames evidenciando esquizócitos, plaquetas 78.000/mm³, TGO 210U/L, TGP 195U/L, LDH elevado. Assinale o diagnóstico e a conduta:", options: ["Síndrome HELLP; estabilização materna e interrupção da gestação", "Colecistite aguda; colecistectomia videolaparoscópica de urgência", "Esteatose hepática aguda da gestação isolada, sem relação com o quadro hematológico", "Hepatite viral aguda; apenas suporte clínico, sem resolução da gestação"], correctIndex: 0, explanation: "Hemólise, elevação de enzimas hepáticas e plaquetopenia em gestante hipertensa caracterizam síndrome HELLP, exigindo estabilização materna e interrupção da gestação pela gravidade do quadro. Colecistite não explica a hemólise nem a plaquetopenia; esteatose hepática aguda é diagnóstico diferencial, mas o quadro com esquizócitos e plaquetopenia é mais característico de HELLP; hepatite viral não explica a hemólise microangiopática associada." },
  { id: "psumg_gerado26_012", banca: "PSU-MG", cycle: "Ciclo Clínico", subject: "Ginecologia e Obstetrícia", text: "Mulher de 31 anos, atraso menstrual de 6 semanas, dor pélvica unilateral e beta-hCG 2.100mUI/mL, ultrassonografia transvaginal sem saco gestacional intrauterino e imagem anexial de 2,5cm, sem líquido livre significativo, hemodinamicamente estável. Assinale a conduta MAIS ADEQUADA:", options: ["Considerar metotrexato, conforme critérios de elegibilidade, ou tratamento cirúrgico", "Laparotomia de urgência, independente da estabilidade hemodinâmica", "Repetir beta-hCG em 30 dias, sem qualquer conduta imediata", "Curetagem uterina, considerando abortamento incompleto como único diagnóstico possível"], correctIndex: 0, explanation: "Beta-hCG positivo sem saco gestacional intrauterino e imagem anexial sugerem gravidez ectópica, podendo ser tratada com metotrexato (conforme critérios de elegibilidade) ou cirurgia em paciente estável. Laparotomia de urgência não é necessária na paciente estável, sem sinais de hemoperitônio significativo; repetir o exame em 30 dias atrasa perigosamente o diagnóstico e tratamento de uma possível ectópica; curetagem uterina não é apropriada sem saco gestacional intrauterino confirmado." },
  { id: "psumg_gerado26_013", banca: "PSU-MG", cycle: "Ciclo Clínico", subject: "Pediatria", text: "Lactente de 3 meses, filho de mãe com sorologia positiva para sífilis não tratada adequadamente na gestação, assintomático ao nascimento. VDRL do recém-nascido: 1:8 (materno 1:4). Assinale a conduta MAIS ADEQUADA:", options: ["Investigação completa (líquor, radiografia de ossos longos, hemograma) e tratamento com penicilina cristalina", "Apenas seguimento sorológico ambulatorial, sem qualquer tratamento", "Tratamento com penicilina benzatina em dose única, sem investigação complementar", "Aguardar sintomas antes de iniciar qualquer investigação ou tratamento"], correctIndex: 0, explanation: "Título do recém-nascido maior que o materno, associado a tratamento materno inadequado, exige investigação completa (líquor, radiografia, hemograma) e tratamento com penicilina cristalina, mesmo em recém-nascido assintomático. Apenas seguimento sorológico sem tratamento é insuficiente diante de critérios de sífilis congênita provável; penicilina benzatina isolada sem investigação de neurossífilis é esquema inadequado para esse cenário de risco; aguardar sintomas atrasa o tratamento de uma infecção congênita já indicada pelos critérios sorológicos e história materna." },
  { id: "psumg_gerado26_014", banca: "PSU-MG", cycle: "Ciclo Clínico", subject: "Pediatria", text: "Menino de 4 anos, com febre há 5 dias, hiperemia conjuntival bilateral não exsudativa, língua em framboesa, edema de extremidades e exantema polimorfo. Ecocardiograma inicial sem alterações coronarianas. Assinale a conduta MAIS ADEQUADA:", options: ["Imunoglobulina intravenosa associada a ácido acetilsalicílico em altas doses", "Apenas antitérmico, sem imunoglobulina, dado o ecocardiograma normal", "Antibioticoterapia empírica isolada, sem imunoglobulina", "Aguardar surgimento de aneurisma coronariano antes de tratar"], correctIndex: 0, explanation: "O quadro é típico de doença de Kawasaki, tratada com imunoglobulina intravenosa e ácido acetilsalicílico, mesmo com ecocardiograma inicial normal, para prevenir o desenvolvimento de aneurisma coronariano. Tratar apenas com antitérmico ignora a necessidade de imunoglobulina para prevenção da complicação coronariana; antibioticoterapia não trata a etiologia inflamatória/imunológica da doença; aguardar o aneurisma já formado perde a janela terapêutica ideal de prevenção." },
  { id: "psumg_gerado26_015", banca: "PSU-MG", cycle: "Ciclo Clínico", subject: "Pediatria", text: "Recém-nascido a termo, 39 semanas, com sialorreia intensa e impossibilidade de progressão de sonda orogástrica, radiografia de tórax evidenciando sonda enrolada na bolsa esofágica proximal, com ar presente no estômago. Assinale a conduta inicial MAIS ADEQUADA:", options: ["Suspensão da via oral, aspiração contínua da bolsa proximal e avaliação cirúrgica", "Alimentação por via oral assistida, sem necessidade de cirurgia", "Espessamento da dieta láctea, sem qualquer intervenção cirúrgica", "Observação clínica isolada por 72 horas, sem qualquer conduta"], correctIndex: 0, explanation: "Sialorreia intensa, impossibilidade de progressão de sonda e ar no estômago (indicando fístula traqueoesofágica distal) confirmam atresia de esôfago, tratada com suspensão da via oral, aspiração contínua da bolsa proximal e avaliação cirúrgica. Alimentação oral assistida é contraindicada diante da impossibilidade anatômica de progressão esofágica; espessamento da dieta não resolve uma obstrução anatômica; observar por 72 horas sem conduta atrasa perigosamente o tratamento de uma malformação com risco de aspiração." },
  { id: "psumg_gerado26_016", banca: "PSU-MG", cycle: "Ciclo Clínico", subject: "Pediatria", text: "Menina de 6 anos, com edema periorbitário matinal progredindo para edema generalizado, urina espumosa, proteinúria maciça, albumina sérica 1,8g/dL, colesterol total 320mg/dL, sem hematúria ou hipertensão relevantes. Assinale o diagnóstico MAIS PROVÁVEL e a resposta terapêutica esperada:", options: ["Síndrome nefrótica por lesão mínima; boa resposta à corticoterapia", "Glomerulonefrite pós-estreptocócica; resolução espontânea sem tratamento medicamentoso", "Síndrome hemolítico-urêmica; plasmaférese como primeira linha em todos os casos", "Pielonefrite aguda; antibioticoterapia isolada, sem relação com a proteinúria"], correctIndex: 0, explanation: "Edema generalizado, proteinúria maciça, hipoalbuminemia e hipercolesterolemia, sem hematúria ou hipertensão significativas, são compatíveis com síndrome nefrótica por lesão mínima, que responde bem à corticoterapia na maioria dos casos. A glomerulonefrite pós-estreptocócica cursa com padrão nefrítico (hematúria, hipertensão), diferente do descrito; a síndrome hemolítico-urêmica cursa com anemia hemolítica microangiopática e plaquetopenia; a pielonefrite não explica a proteinúria maciça com hipoalbuminemia e hipercolesterolemia." },
  { id: "psumg_gerado26_017", banca: "PSU-MG", cycle: "Ciclo Clínico", subject: "Pediatria", text: "Lactente de 2 meses, com tosse paroxística seguida de guincho inspiratório e cianose, sem febre, mãe relatando contato domiciliar com adulto tossindo há semanas. Leucocitose com linfocitose importante. Assinale o diagnóstico e a conduta:", options: ["Coqueluche; macrolídeo associado a suporte respiratório conforme necessidade", "Bronquiolite viral aguda; apenas suporte clínico, sem investigação do contactante", "Asma brônquica; broncodilatador isolado, sem antibioticoterapia", "Refluxo gastroesofágico; espessamento da dieta láctea, sem antimicrobiano"], correctIndex: 0, explanation: "Tosse paroxística com guincho, cianose, ausência de febre, linfocitose e contactante com tosse prolongada sugerem coqueluche, tratada com macrolídeo e suporte respiratório. A bronquiolite cursa tipicamente com sibilância e desconforto respiratório, não com esse padrão de guincho paroxístico; a asma é rara nessa idade e não explica o contexto epidemiológico; o refluxo não explica a linfocitose nem o contexto do contactante." },
  { id: "psumg_gerado26_018", banca: "PSU-MG", cycle: "Ciclo Clínico", subject: "Pediatria", text: "Menino de 8 anos, com dor articular migratória em grandes articulações, cardite com sopro novo, nódulos subcutâneos, VHS 80mm/h e ASLO 800UI/mL, faringite estreptocócica há 3 semanas. Assinale a alternativa CORRETA sobre os critérios diagnósticos:", options: ["Dois critérios maiores (artrite, cardite, nódulos) associados a evidência de infecção estreptocócica prévia preenchem os critérios de Jones", "Um único critério menor isolado é suficiente para o diagnóstico, independente de critério maior", "O diagnóstico dispensa qualquer evidência de infecção estreptocócica prévia", "Os critérios de Jones se baseiam exclusivamente em achados ecocardiográficos"], correctIndex: 0, explanation: "Os critérios de Jones exigem, associados a evidência de infecção estreptocócica prévia, dois critérios maiores (como artrite, cardite, nódulos subcutâneos) ou um maior e dois menores. Um único critério menor isolado não é suficiente para o diagnóstico; a evidência de infecção estreptocócica prévia é exigência central dos critérios, não dispensável; o diagnóstico não se baseia exclusivamente em achados ecocardiográficos, sendo um conjunto de critérios clínicos e laboratoriais." },
  { id: "psumg_gerado26_019", banca: "PSU-MG", cycle: "Ciclo Clínico", subject: "Pediatria", text: "Recém-nascido pré-termo de 30 semanas, em ventilação mecânica desde o nascimento, aos 12 dias apresenta distensão abdominal, resíduo gástrico bilioso e pneumatose intestinal na radiografia. Assinale a conduta inicial MAIS ADEQUADA:", options: ["Suspensão da dieta enteral, antibioticoterapia sistêmica e suporte clínico", "Manutenção da dieta enteral com espessamento, sem suspensão da via oral", "Apendicectomia de urgência, sem suporte clínico prévio", "Gastrostomia isolada, sem qualquer suporte clínico adicional"], correctIndex: 0, explanation: "Distensão abdominal, resíduo bilioso e pneumatose intestinal em prematuro são achados clássicos de enterocolite necrosante, tratada com suspensão da dieta enteral, antibioticoterapia e suporte clínico. Manter a dieta enteral agravaria o quadro isquêmico intestinal; apendicite neonatal é extremamente rara e não é a hipótese mais provável nesse contexto; gastrostomia isolada não trata o processo infeccioso/isquêmico intestinal agudo em curso." },
  { id: "psumg_gerado26_020", banca: "PSU-MG", cycle: "Ciclo Clínico", subject: "Pediatria", text: "Menina de 10 meses, com choro intenso intermitente, flexão de membros inferiores, palidez durante as crises e fezes com sangue e muco (aspecto de \"geleia de framboesa\"). Assinale o exame inicial MAIS ADEQUADO:", options: ["Ultrassonografia abdominal, com posterior tentativa de redução por enema conforme achados", "Tomografia computadorizada de abdome como exame inicial de escolha", "Colonoscopia terapêutica de urgência, sem exame de imagem prévio", "Apenas hidratação oral, sem qualquer exame de imagem"], correctIndex: 0, explanation: "Dor em cólica com flexão de membros, palidez e fezes em \"geleia de framboesa\" sugerem invaginação intestinal, investigada inicialmente por ultrassonografia, com tentativa de redução por enema conforme os achados. Tomografia não é o exame inicial preferido nessa faixa etária pela radiação; colonoscopia não é o método padrão de redução da invaginação; hidratação oral isolada não resolve a obstrução mecânica intestinal." },
  { id: "psumg_gerado26_021", banca: "PSU-MG", cycle: "Ciclo Clínico", subject: "Cirurgia Geral", text: "Homem de 34 anos, vítima de acidente motociclístico, hipotenso (PA 78/50mmHg), taquicárdico, com distensão abdominal e FAST positivo com líquido livre perihepático e periesplênico. Assinale a conduta MAIS ADEQUADA:", options: ["Laparotomia exploradora de urgência", "Tomografia computadorizada de abdome antes de qualquer decisão cirúrgica", "Observação clínica isolada por 24 horas", "Alta hospitalar após analgesia, dado o FAST positivo isolado"], correctIndex: 0, explanation: "Paciente instável com FAST positivo tem indicação de laparotomia exploradora de urgência, sem necessidade de aguardar tomografia. Tomografia é apropriada apenas em pacientes estáveis; observação isolada é perigosa diante de instabilidade hemodinâmica com sangramento provável; alta hospitalar ignora completamente a gravidade do achado." },
  { id: "psumg_gerado26_022", banca: "PSU-MG", cycle: "Ciclo Clínico", subject: "Cirurgia Geral", text: "Mulher de 52 anos, com dor em hipocôndrio direito há 12 horas, febre de 38,6°C, Murphy positivo, ultrassonografia evidenciando parede vesicular espessada (5mm) e cálculo impactado no colo. Leucócitos 14.200/mm³. Assinale a conduta MAIS ADEQUADA:", options: ["Colecistectomia videolaparoscópica precoce (nas primeiras 72 horas)", "Tratamento clínico exclusivo com antibiótico, sem cirurgia em nenhum momento", "Colecistectomia eletiva após 6 semanas de tratamento clínico exclusivo", "CPRE de urgência, independente de sinais de coledocolitíase"], correctIndex: 0, explanation: "Colecistite aguda tem indicação de colecistectomia videolaparoscópica precoce, idealmente nas primeiras 72 horas, associada a antibioticoterapia. Tratamento clínico exclusivo sem cirurgia expõe a paciente a risco de recorrência e complicações; postergar a cirurgia para 6 semanas não é a abordagem preferida atualmente, quando a cirurgia precoce é factível; CPRE não é rotina sem sinais de obstrução de via biliar principal." },
  { id: "psumg_gerado26_023", banca: "PSU-MG", cycle: "Ciclo Clínico", subject: "Cirurgia Geral", text: "Homem de 60 anos, tabagista, disfagia progressiva primeiro para sólidos e depois líquidos, perda de 12kg, endoscopia com lesão vegetante em terço médio do esôfago, biópsia confirmando carcinoma espinocelular. Assinale a conduta MAIS ADEQUADA antes de definir o tratamento:", options: ["Estadiamento com tomografia de tórax/abdome e ecoendoscopia, quando indicada", "Esofagectomia imediata, sem qualquer estadiamento prévio", "Radioterapia paliativa isolada, sem investigação estadiadora", "Quimioterapia isolada sem estadiamento prévio"], correctIndex: 0, explanation: "Após confirmação histológica, o estadiamento com tomografia e ecoendoscopia (quando indicada) é essencial para definir a extensão e a estratégia terapêutica. Esofagectomia sem estadiamento pode submeter o paciente a cirurgia inadequada para o estágio real; radioterapia paliativa isolada sem estadiamento não permite avaliar potencial curativo; quimioterapia isolada sem estadiamento não define adequadamente a estratégia terapêutica global." },
  { id: "psumg_gerado26_024", banca: "PSU-MG", cycle: "Ciclo Clínico", subject: "Cirurgia Geral", text: "Mulher de 45 anos, obesa, com dor intensa em fossa ilíaca esquerda, febre baixa, tomografia evidenciando espessamento de parede colônica com divertículos e borramento de gordura pericólica, sem abscesso ou perfuração livre. Assinale a conduta MAIS ADEQUADA:", options: ["Tratamento clínico com antibioticoterapia e dieta conforme tolerância", "Colectomia de urgência, independente da gravidade", "Colonoscopia de urgência imediata, independente do risco de perfuração", "Apenas analgesia, sem qualquer antibioticoterapia"], correctIndex: 0, explanation: "Diverticulite aguda não complicada é tratada clinicamente com antibioticoterapia e dieta conforme tolerância, reservando cirurgia para complicações. Colectomia de urgência é desproporcional para a forma não complicada; colonoscopia na fase aguda é geralmente postergada pelo risco de perfuração; não tratar com antibiótico ignora o processo infeccioso/inflamatório presente." },
  { id: "psumg_gerado26_025", banca: "PSU-MG", cycle: "Ciclo Clínico", subject: "Cirurgia Geral", text: "Homem de 55 anos, com massa abdominal pulsátil assintomática, ultrassonografia confirmando aneurisma de aorta abdominal infrarrenal de 5,8cm. Assinale a conduta MAIS ADEQUADA:", options: ["Correção cirúrgica eletiva (aberta ou endovascular)", "Acompanhamento ultrassonográfico seriado anual, sem intervenção", "Anticoagulação plena isolada, sem qualquer intervenção sobre o aneurisma", "Observação clínica exclusiva até que o paciente se torne sintomático"], correctIndex: 0, explanation: "Aneurisma acima de 5,5cm tem indicação de correção eletiva pelo risco progressivo de rotura. Acompanhamento seriado é apropriado para aneurismas menores, abaixo do limiar cirúrgico; anticoagulação plena não trata o risco de rotura; aguardar sintomas é perigoso, pois podem indicar rotura iminente." },
  { id: "psumg_gerado26_026", banca: "PSU-MG", cycle: "Ciclo Clínico", subject: "Cirurgia Geral", text: "Homem de 28 anos, com dor abdominal iniciada em região periumbilical há 18 horas, migrando para fossa ilíaca direita, com Blumberg positivo, febre de 38,2°C, leucócitos 15.600/mm³, tomografia evidenciando apêndice espessado com estrato periapendicular. Assinale a conduta MAIS ADEQUADA:", options: ["Apendicectomia (aberta ou laparoscópica)", "Tratamento antibiótico isolado, dispensando qualquer cirurgia nesse caso", "Observação isolada por 48 horas, sem tratamento cirúrgico ou antibiótico", "Colonoscopia de urgência, antes de qualquer decisão terapêutica"], correctIndex: 0, explanation: "Apendicite aguda confirmada por imagem tem indicação de apendicectomia como tratamento padrão-ouro. Tratamento antibiótico isolado é opção apenas em casos muito selecionados e não é a conduta padrão diante desse quadro; observação isolada por 48 horas aumenta o risco de perfuração; colonoscopia não é indicada na fase aguda de apendicite, com risco de perfuração." },
  { id: "psumg_gerado26_027", banca: "PSU-MG", cycle: "Ciclo Clínico", subject: "Saúde Coletiva", text: "Em um estudo de coorte prospectivo, a incidência de câncer de pulmão em fumantes foi de 20 por 1.000 pessoas-ano e em não fumantes de 2 por 1.000 pessoas-ano. Assinale o risco relativo do tabagismo para câncer de pulmão nesse estudo:", options: ["10", "0,1", "18", "22"], correctIndex: 0, explanation: "O risco relativo é a razão entre as incidências (20/2 = 10). Inverter a razão (0,1) confundiria o risco relativo com seu recíproco; 18 corresponde ao risco atribuível (diferença entre as incidências), não ao risco relativo; 22 corresponde à soma das incidências, sem significado epidemiológico nesse contexto." },
  { id: "psumg_gerado26_028", banca: "PSU-MG", cycle: "Ciclo Clínico", subject: "Saúde Coletiva", text: "Em relação à Notificação Compulsória de doenças, assinale a alternativa ERRADA:", options: ["Doenças de notificação compulsória imediata podem ser comunicadas em até 30 dias, sem prejuízo à vigilância", "A notificação compulsória é obrigação de todo profissional de saúde e de serviços públicos e privados", "A lista nacional de doenças de notificação compulsória é definida por portaria do Ministério da Saúde", "Algumas doenças exigem notificação em até 24 horas, dado seu potencial de disseminação"], correctIndex: 0, explanation: "É incorreto afirmar que doenças de notificação imediata podem aguardar 30 dias, pois essas exigem comunicação em prazo muito mais curto (geralmente até 24 horas), dado o risco de disseminação. As demais afirmações são corretas quanto à obrigatoriedade da notificação, à definição por portaria ministerial e ao prazo de 24 horas para doenças de notificação imediata." },
  { id: "psumg_gerado26_029", banca: "PSU-MG", cycle: "Ciclo Clínico", subject: "Saúde Coletiva", text: "Em relação aos atributos da Atenção Primária à Saúde, assinale a alternativa CORRETA sobre a longitudinalidade:", options: ["Refere-se à manutenção de vínculo continuado entre a equipe e a população ao longo do tempo, independente de doenças específicas", "Refere-se à capacidade de resolver a maioria dos problemas na própria unidade, sem necessidade de referência", "Refere-se à oferta simultânea de múltiplos serviços especializados em uma única unidade", "Refere-se exclusivamente à coordenação do cuidado entre diferentes níveis de atenção"], correctIndex: 0, explanation: "A longitudinalidade refere-se à manutenção de vínculo continuado entre equipe e população ao longo do tempo, independente da presença de doenças específicas. A resolução da maioria dos problemas na própria unidade descreve integralidade/resolutividade, não longitudinalidade; a oferta simultânea de múltiplos serviços especializados não é atributo da atenção primária; a coordenação entre níveis descreve outro atributo distinto." },
  { id: "psumg_gerado26_030", banca: "PSU-MG", cycle: "Ciclo Clínico", subject: "Saúde Coletiva", text: "Em um teste diagnóstico aplicado a 300 pacientes com a doença e 700 sem a doença, o teste foi positivo em 270 dos doentes e em 70 dos não doentes. Assinale a sensibilidade e a especificidade do teste, respectivamente:", options: ["90% e 90%", "90% e 70%", "77% e 90%", "70% e 90%"], correctIndex: 0, explanation: "A sensibilidade é a proporção de doentes corretamente identificados (270/300 = 90%) e a especificidade é a proporção de não doentes corretamente identificados como negativos (630/700 = 90%). As demais combinações não correspondem aos cálculos corretos com os números fornecidos." },
  { id: "psumg_gerado26_031", banca: "PSU-MG", cycle: "Ciclo Clínico", subject: "Saúde Coletiva", text: "Em relação à vigilância epidemiológica sentinela, assinale a alternativa CORRETA:", options: ["Monitora uma amostra selecionada de serviços ou populações representativas, sem exigir cobertura universal", "Exige cobertura de 100% de todos os serviços de saúde do país", "É aplicável exclusivamente a doenças crônicas não transmissíveis", "Substitui integralmente a notificação compulsória universal para todas as doenças"], correctIndex: 0, explanation: "A vigilância sentinela monitora uma amostra selecionada e representativa, permitindo identificar tendências sem exigir cobertura universal. Não exige cobertura de 100%; não se aplica exclusivamente a doenças crônicas, sendo usada também para doenças transmissíveis; não substitui integralmente a notificação compulsória universal, coexistindo com ela." },
  { id: "psumg_gerado26_032", banca: "PSU-MG", cycle: "Ciclo Clínico", subject: "Saúde Coletiva", text: "Em relação ao acolhimento com classificação de risco, assinale a alternativa CORRETA:", options: ["Reorganiza o processo de trabalho para priorizar o atendimento conforme gravidade clínica e vulnerabilidade", "Tem como único critério válido a ordem cronológica de chegada", "É aplicável exclusivamente a serviços de urgência hospitalar", "Elimina completamente a necessidade de triagem em qualquer nível de atenção"], correctIndex: 0, explanation: "O acolhimento com classificação de risco reorganiza o atendimento priorizando gravidade e vulnerabilidade, não apenas a ordem de chegada. Considerar apenas a ordem cronológica contraria o princípio do modelo; é aplicável também na atenção primária, não exclusivo de urgência hospitalar; não elimina a necessidade de triagem, sendo ele próprio um processo de triagem qualificada." },
  { id: "psumg_gerado26_033", banca: "PSU-MG", cycle: "Ciclo Clínico", subject: "Saúde Coletiva", text: "Em relação aos indicadores de mortalidade materna, assinale a alternativa CORRETA sobre a fórmula da razão de mortalidade materna:", options: ["Número de óbitos maternos dividido pelo número de nascidos vivos, multiplicado por 100.000", "Número de óbitos maternos dividido pela população total, multiplicado por 1.000", "Número de óbitos maternos dividido pelo número de óbitos infantis, multiplicado por 100", "Número de óbitos maternos dividido pelo número de partos hospitalares, multiplicado por 10"], correctIndex: 0, explanation: "A razão de mortalidade materna é o número de óbitos maternos dividido pelo número de nascidos vivos no período, multiplicado por 100.000. As demais fórmulas não correspondem à padronização internacional desse indicador." },
  { id: "psumg_gerado26_034", banca: "PSU-MG", cycle: "Ciclo Clínico", subject: "Saúde Coletiva", text: "Em relação ao viés de seleção em estudos caso-controle hospitalares, assinale a alternativa CORRETA:", options: ["Pacientes mais graves tendem a ser mais frequentemente incluídos, distorcendo a associação estudada (viés de Berkson)", "Refere-se à forma diferencial de medir a exposição entre casos e controles", "Decorre de uma terceira variável associada à exposição e ao desfecho", "Refere-se à maior probabilidade de publicação de estudos com resultados positivos"], correctIndex: 0, explanation: "O viés de seleção em estudos caso-controle hospitalares, classicamente descrito como viés de Berkson, ocorre quando pacientes mais graves são mais frequentemente incluídos, distorcendo a associação. A medição diferencial da exposição descreve viés de aferição; a terceira variável associada descreve confusão; a maior probabilidade de publicação de resultados positivos descreve viés de publicação." },
  { id: "psumg_gerado26_035", banca: "PSU-MG", cycle: "Ciclo Clínico", subject: "Infectologia", text: "Homem de 32 anos, retorna de área endêmica com febre alta, mialgia intensa, exantema no 4º dia, dor abdominal intensa persistente e sangramento gengival. Plaquetas 68.000/mm³; hematócrito elevado em relação ao basal. Assinale a classificação de gravidade e a conduta:", options: ["Dengue com sinais de alarme; internação para hidratação venosa e monitorização", "Dengue sem sinais de alarme; alta com hidratação oral apenas", "Febre amarela; vacinação imediata como tratamento", "Chikungunya; apenas analgesia, sem necessidade de internação"], correctIndex: 0, explanation: "Dor abdominal intensa persistente, sangramento e hemoconcentração são sinais de alarme na dengue, exigindo internação para hidratação venosa e monitorização. Classificar como dengue sem sinais de alarme ignora os sinais presentes; vacinação não trata febre amarela já instalada; chikungunya não costuma cursar com esses sinais de alarme hemorrágicos tão específicos da dengue." },
  { id: "psumg_gerado26_036", banca: "PSU-MG", cycle: "Ciclo Clínico", subject: "Infectologia", text: "Homem de 38 anos, HIV positivo, CD4 de 85 células/mm³, com cefaleia progressiva, ressonância evidenciando lesão com realce em anel em núcleos da base. Assinale o tratamento empírico inicial MAIS ADEQUADO:", options: ["Sulfadiazina associada a pirimetamina e ácido folínico", "Ceftriaxona isolada", "Anfotericina B isolada, sem investigação de imagem", "Quimioterapia isolada, sem tratamento empírico prévio"], correctIndex: 0, explanation: "Lesão com realce em anel em núcleos da base em paciente com CD4 baixo sugere neurotoxoplasmose, tratada empiricamente com sulfadiazina, pirimetamina e ácido folínico. Ceftriaxona cobre bactérias, não o protozoário; anfotericina B é direcionada a fungos; quimioterapia seria voltada a linfoma primário do SNC, considerada apenas após falha do tratamento empírico." },
  { id: "psumg_gerado26_037", banca: "PSU-MG", cycle: "Ciclo Clínico", subject: "Infectologia", text: "Homem de 45 anos, com tosse produtiva há 5 semanas, febre vespertina, sudorese noturna, baciloscopia positiva para BAAR. Assinale o esquema terapêutico padrão sem tratamento prévio:", options: ["RIPE por 2 meses, seguido de rifampicina e isoniazida por 4 meses", "Isoniazida isolada por 6 meses", "Rifampicina isolada por 12 meses", "Etambutol e pirazinamida isolados por 6 meses"], correctIndex: 0, explanation: "O esquema básico para tuberculose virgem de tratamento é 2 meses de quatro drogas (RIPE) seguidos de 4 meses de rifampicina e isoniazida. Isoniazida isolada por 6 meses é esquema de infecção latente; rifampicina isolada e etambutol/pirazinamida isolados não constituem esquemas padrão adequados." },
  { id: "psumg_gerado26_038", banca: "PSU-MG", cycle: "Ciclo Clínico", subject: "Infectologia", text: "Mulher de 26 anos, com febre, exantema petequial em extremidades, cefaleia intensa e rigidez de nuca, líquor turvo com predomínio de neutrófilos, glicose baixa e proteína elevada. Assinale a conduta MAIS ADEQUADA:", options: ["Antibioticoterapia empírica imediata, sem aguardar resultado de cultura", "Aguardar resultado da cultura do líquor antes de iniciar qualquer antibiótico", "Corticoide isolado, sem antibioticoterapia", "Apenas antitérmico, aguardando resolução espontânea"], correctIndex: 0, explanation: "Suspeita clínica de meningite bacteriana com líquor turvo, predomínio de neutrófilos, glicose baixa e proteína elevada exige antibioticoterapia empírica imediata, sem aguardar cultura, dado o risco de deterioração rápida. Aguardar cultura atrasa perigosamente o tratamento; corticoide isolado sem antibiótico não trata a infecção bacteriana; apenas antitérmico ignora uma emergência infecciosa grave." },
  { id: "psumg_gerado26_039", banca: "PSU-MG", cycle: "Ciclo Clínico", subject: "Infectologia", text: "Homem de 40 anos, com úlcera genital única, indolor, de bordas endurecidas, linfadenopatia inguinal não dolorosa, VDRL reagente 1:64 e FTA-ABS reagente. Assinale o tratamento de escolha:", options: ["Penicilina G benzatina em dose única", "Azitromicina em dose única", "Doxiciclina por 21 dias", "Aciclovir por 7 a 10 dias"], correctIndex: 0, explanation: "Úlcera única, indolor, de bordas endurecidas (cancro duro) com sorologias treponêmica e não treponêmica reagentes confirma sífilis primária, tratada com penicilina G benzatina. Azitromicina em dose única é usada para cancro mole; doxiciclina por 21 dias é usada para linfogranuloma venéreo; aciclovir é usado para herpes genital, quadro clinicamente distinto." },
  { id: "psumg_gerado26_040", banca: "PSU-MG", cycle: "Ciclo Clínico", subject: "Pneumologia", text: "Homem de 26 anos, longilíneo, com dor torácica súbita e dispneia, ausculta com murmúrio vesicular abolido em hemitórax direito, radiografia com linha de pleura visceral deslocada, ocupando cerca de 15% do hemitórax, sem desvio de mediastino. Assinale a conduta MAIS ADEQUADA:", options: ["Observação clínica com oxigenoterapia suplementar", "Drenagem torácica em selo d'água obrigatória, independente do volume", "Toracotomia de urgência, independente da estabilidade clínica", "Pleurodese química imediata no primeiro episódio"], correctIndex: 0, explanation: "Pneumotórax de pequeno volume em paciente estável pode ser conduzido com observação e oxigenoterapia suplementar. Drenagem obrigatória em todos os casos ignora a possibilidade de manejo conservador em pneumotórax pequeno; toracotomia de urgência é desproporcional; pleurodese não é indicada no primeiro episódio de pequeno volume." },
  { id: "psumg_gerado26_041", banca: "PSU-MG", cycle: "Ciclo Clínico", subject: "Pneumologia", text: "Mulher de 58 anos, tabagista, com dispneia progressiva, tosse crônica produtiva, espirometria com VEF1/CVF reduzida sem resposta significativa ao broncodilatador. Assinale a intervenção com MAIOR impacto na progressão da doença:", options: ["Cessação do tabagismo", "Corticoide inalatório isolado em alta dose", "Antibioticoterapia profilática contínua", "Oxigenoterapia domiciliar contínua, independente da saturação"], correctIndex: 0, explanation: "Na DPOC, a cessação do tabagismo é a intervenção com maior impacto comprovado na progressão da doença. Corticoide inalatório isolado não tem o mesmo impacto na progressão; antibioticoterapia profilática contínua não é a intervenção de maior impacto; oxigenoterapia domiciliar é indicada apenas com hipoxemia significativa comprovada, não em todo paciente." },
  { id: "psumg_gerado26_042", banca: "PSU-MG", cycle: "Ciclo Clínico", subject: "Pneumologia", text: "Homem de 60 anos, com dispneia progressiva, baqueteamento digital, crepitações finas em velcro em bases bilateralmente, tomografia com faveolamento subpleural predominante em bases. Assinale a alternativa CORRETA sobre o tratamento farmacológico específico:", options: ["Antifibróticos podem retardar a progressão da perda funcional, sem reverter a fibrose já estabelecida", "Corticoide sistêmico isolado em altas doses é o tratamento de escolha, com reversão completa da fibrose", "O transplante pulmonar é contraindicado em qualquer estágio dessa doença", "Antibioticoterapia profilática contínua reverte o padrão fibrótico"], correctIndex: 0, explanation: "Na fibrose pulmonar idiopática, os antifibróticos podem retardar a progressão funcional, mas não revertem a fibrose já estabelecida. Corticoide isolado não é o tratamento de escolha nessa condição específica; transplante pulmonar é opção válida em estágios avançados selecionados; antibioticoterapia não reverte o padrão fibrótico, que não tem causa infecciosa." },
  { id: "psumg_gerado26_043", banca: "PSU-MG", cycle: "Ciclo Clínico", subject: "Pneumologia", text: "Mulher de 35 anos, pós-operatório de artroplastia de quadril há 6 dias, dispneia súbita, taquicardia, dor pleurítica, Wells alto. Assinale a conduta MAIS ADEQUADA:", options: ["Iniciar anticoagulação empírica e prosseguir com angiotomografia de tórax", "Aguardar angiotomografia antes de qualquer anticoagulação", "Solicitar apenas radiografia de tórax como exame definitivo", "Trombolítico sistêmico imediato, independente de instabilidade hemodinâmica"], correctIndex: 0, explanation: "Em paciente com alta probabilidade clínica de TEP, a anticoagulação empírica deve ser iniciada enquanto se prossegue a investigação por imagem. Aguardar a angiotomografia sem anticoagulação expõe a risco de progressão; radiografia de tórax não é exame definitivo para TEP; trombolítico sistêmico é reservado a instabilidade hemodinâmica (TEP maciço), não de rotina." },
  { id: "psumg_gerado26_044", banca: "PSU-MG", cycle: "Ciclo Clínico", subject: "Gastroenterologia", text: "Homem de 50 anos, etilista, com dor abdominal em faixa irradiada para o dorso após libação alcoólica, lipase 750U/L (referência até 160). Assinale a conduta inicial MAIS ADEQUADA:", options: ["Hidratação venosa vigorosa, analgesia e dieta conforme tolerância", "Antibioticoterapia profilática de rotina", "Cirurgia pancreática imediata", "Jejum absoluto prolongado por 2 semanas, independente da evolução"], correctIndex: 0, explanation: "O tratamento inicial da pancreatite aguda é hidratação venosa vigorosa, analgesia e dieta conforme tolerância, sem antibiótico profilático de rotina. Cirurgia imediata não é indicada na fase inicial não complicada; jejum absoluto prolongado sem necessidade prejudica a recuperação, sendo a dieta precoce a conduta atual preferida." },
  { id: "psumg_gerado26_045", banca: "PSU-MG", cycle: "Ciclo Clínico", subject: "Gastroenterologia", text: "Mulher de 48 anos, com fadiga, prurido e elevação isolada de fosfatase alcalina, anticorpo antimitocôndria positivo. Assinale o diagnóstico MAIS PROVÁVEL:", options: ["Colangite biliar primária", "Colangite esclerosante primária", "Hepatite autoimune", "Doença de Wilson"], correctIndex: 0, explanation: "Prurido, colestase isolada e anticorpo antimitocôndria positivo são marcadores clássicos da colangite biliar primária. A colangite esclerosante tem padrão colangiográfico próprio e antimitocôndria negativo; a hepatite autoimune tem outro perfil sorológico; a doença de Wilson acomete pacientes jovens, sem relação com esse autoanticorpo." },
  { id: "psumg_gerado26_046", banca: "PSU-MG", cycle: "Ciclo Clínico", subject: "Gastroenterologia", text: "Homem de 62 anos, com hematêmese volumosa, história de cirrose hepática por álcool, PA 84/56mmHg, FC 122bpm. Endoscopia de urgência evidenciando varizes esofágicas com sangramento ativo. Assinale a conduta MAIS ADEQUADA, além da ressuscitação volêmica:", options: ["Terlipressina IV associada a ligadura elástica endoscópica das varizes e antibioticoterapia profilática", "Apenas ligadura endoscópica, sem terlipressina ou antibiótico", "Balão de Sengstaken-Blakemore como primeira medida, antes de qualquer endoscopia", "Betabloqueador IV em altas doses como principal medida hemostática"], correctIndex: 0, explanation: "Sangramento por varizes esofágicas em cirrótico é tratado com terlipressina (vasoconstritor esplâncnico), ligadura elástica endoscópica e antibioticoterapia profilática, que reduz mortalidade nesse contexto. Apenas ligadura sem terlipressina e antibiótico não segue o protocolo completo recomendado; o balão de Sengstaken-Blakemore é medida de resgate temporário, não a primeira medida antes da endoscopia; betabloqueador IV não é a principal medida hemostática aguda, sendo usado na profilaxia posterior por via oral." },
  { id: "psumg_gerado26_047", banca: "PSU-MG", cycle: "Ciclo Clínico", subject: "Gastroenterologia", text: "Mulher de 28 anos, com diarreia crônica, distensão abdominal e anemia ferropriva refratária a ferro oral, sorologia positiva para antitransglutaminase IgA. Assinale o tratamento indicado:", options: ["Dieta isenta de glúten", "Corticoide isolado", "Antibiótico de amplo espectro", "Dieta isenta de lactose"], correctIndex: 0, explanation: "Anticorpos antitransglutaminase positivos confirmam doença celíaca, tratada com dieta isenta de glúten por toda a vida. Corticoide isolado não trata a causa autoimune desencadeada pelo glúten; antibiótico não tem papel nessa enteropatia não infecciosa; dieta isenta de lactose trataria intolerância à lactose, condição distinta." },
  { id: "psumg_gerado26_048", banca: "PSU-MG", cycle: "Ciclo Clínico", subject: "Gastroenterologia", text: "Homem de 55 anos, com icterícia progressiva indolor, colúria, acolia fecal, tomografia evidenciando massa em cabeça de pâncreas com dilatação de vias biliares. Assinale o diagnóstico MAIS PROVÁVEL e a conduta de investigação:", options: ["Adenocarcinoma de pâncreas; colangiorressonância e biópsia guiada por ecoendoscopia, com avaliação de ressecabilidade", "Pancreatite aguda biliar; apenas analgesia e hidratação, sem investigação de massa", "Colelitíase assintomática; observação clínica isolada", "Hepatite viral aguda; sorologias virais como único exame necessário"], correctIndex: 0, explanation: "Icterícia indolor progressiva com massa em cabeça de pâncreas é altamente sugestiva de adenocarcinoma de pâncreas, exigindo investigação complementar e avaliação de ressecabilidade. Pancreatite biliar não explica a massa pancreática; colelitíase assintomática não explica icterícia obstrutiva; hepatite viral não explica a massa identificada na tomografia." },
  { id: "psumg_gerado26_049", banca: "PSU-MG", cycle: "Ciclo Clínico", subject: "Medicina de Família", text: "Em relação ao método clínico centrado na pessoa, assinale a alternativa CORRETA:", options: ["Busca compreender a doença e a experiência de adoecimento, considerando contexto familiar e social", "Prioriza exclusivamente o diagnóstico biomédico, sem espaço para expectativas do paciente", "Restringe a decisão terapêutica exclusivamente ao médico, sem participação do paciente", "É aplicável apenas em consultas de longa duração"], correctIndex: 0, explanation: "O método clínico centrado na pessoa busca compreender a doença e a experiência de adoecimento, considerando o contexto familiar e social. Priorizar exclusivamente o diagnóstico biomédico contraria a essência do método; restringir a decisão exclusivamente ao médico contraria o princípio de decisão compartilhada; o método pode ser aplicado mesmo em consultas breves." },
  { id: "psumg_gerado26_050", banca: "PSU-MG", cycle: "Ciclo Clínico", subject: "Medicina de Família", text: "Em relação à prevenção quaternária, assinale a alternativa CORRETA:", options: ["Busca evitar intervenções médicas desnecessárias ou potencialmente prejudiciais", "Tem como objetivo aumentar sistematicamente o número de exames solicitados por consulta", "Aplica-se exclusivamente a pacientes oncológicos em cuidados paliativos", "É sinônimo de prevenção terciária, sem qualquer distinção conceitual"], correctIndex: 0, explanation: "A prevenção quaternária busca proteger o paciente de intervenções desnecessárias ou potencialmente prejudiciais. Aumentar sistematicamente exames contraria diretamente esse objetivo; não se restringe a pacientes oncológicos paliativos; não é sinônimo de prevenção terciária, sendo conceito distinto." },
  { id: "psumg_gerado26_051", banca: "PSU-MG", cycle: "Ciclo Clínico", subject: "Medicina de Família", text: "Em relação ao território adscrito na Estratégia Saúde da Família, assinale a alternativa CORRETA:", options: ["Refere-se à área geográfica delimitada com população definida sob responsabilidade de uma equipe de saúde", "Refere-se exclusivamente aos limites administrativos municipais", "Refere-se à área de atuação restrita a hospitais terciários e quaternários", "É aplicável exclusivamente a áreas rurais"], correctIndex: 0, explanation: "O território adscrito refere-se à área geográfica delimitada com população definida, sob responsabilidade de uma equipe de saúde da família. Não se limita aos limites administrativos municipais; não se refere à atuação de hospitais terciários; é aplicável tanto a contextos urbanos quanto rurais." },
  { id: "psumg_gerado26_052", banca: "PSU-MG", cycle: "Ciclo Clínico", subject: "Hematologia", text: "Homem de 65 anos, com fadiga, dor óssea lombar, anemia normocítica, insuficiência renal e hipercalcemia, eletroforese de proteínas com pico monoclonal. Assinale o diagnóstico MAIS PROVÁVEL:", options: ["Mieloma múltiplo", "Leucemia mieloide aguda", "Linfoma de Hodgkin", "Policitemia vera"], correctIndex: 0, explanation: "Dor óssea, anemia, insuficiência renal, hipercalcemia e componente monoclonal formam a tétrade clássica do mieloma múltiplo. A leucemia mieloide aguda cursaria com pancitopenia e blastos circulantes; o linfoma de Hodgkin cursa com linfadenopatia e sintomas B; a policitemia vera cursa com poliglobulia, quadro oposto à anemia descrita." },
  { id: "psumg_gerado26_053", banca: "PSU-MG", cycle: "Ciclo Clínico", subject: "Hematologia", text: "Menina de 6 anos, com palidez, icterícia leve, esplenomegalia, esfregaço com esferócitos, fragilidade osmótica alterada, Coombs direto negativo. Assinale o diagnóstico MAIS PROVÁVEL:", options: ["Esferocitose hereditária", "Anemia falciforme", "Anemia hemolítica autoimune", "Talassemia major"], correctIndex: 0, explanation: "Esferócitos com fragilidade osmótica aumentada e Coombs direto negativo são característicos da esferocitose hereditária. A anemia falciforme apresentaria hemácias em foice; a anemia hemolítica autoimune teria Coombs direto positivo; a talassemia major cursaria com hemácias em alvo, não esferócitos." },
  { id: "psumg_gerado26_054", banca: "PSU-MG", cycle: "Ciclo Clínico", subject: "Hematologia", text: "Homem de 70 anos, com anemia normocítica, insuficiência renal e proteinúria não nefrótica, eletroforese com pico monoclonal. Assinale a investigação MAIS ADEQUADA:", options: ["Dosagem de cadeias leves livres séricas e mielograma", "Apenas reposição de ferro, sem outra investigação", "Biópsia renal isolada, sem avaliação hematológica", "Ultrassonografia renal isolada, sem outra investigação"], correctIndex: 0, explanation: "Componente monoclonal com anemia e insuficiência renal exige investigação hematológica dirigida para excluir mieloma múltiplo. Reposição de ferro isolada ignora o achado monoclonal; biópsia renal isolada não elucida a causa hematológica; ultrassonografia renal isolada não investiga a discrasia plasmocitária." },
  { id: "psumg_gerado26_055", banca: "PSU-MG", cycle: "Ciclo Clínico", subject: "Endocrinologia", text: "Mulher de 32 anos, com perda de peso, taquicardia, tremores finos, exoftalmia bilateral, TSH suprimido e T4 livre elevado. Assinale o tratamento inicial MAIS ADEQUADO:", options: ["Tionamida antitireoidiana (como metimazol)", "Levotiroxina", "Observação clínica isolada, sem tratamento medicamentoso", "Cirurgia transesfenoidal imediata"], correctIndex: 0, explanation: "Exoftalmia, bócio e hipertireoidismo laboratorial confirmam doença de Graves, tratada inicialmente com tionamida antitireoidiana. Levotiroxina trataria hipotireoidismo, quadro oposto; observação isolada ignora um hipertireoidismo florido; cirurgia transesfenoidal é para adenoma hipofisário, não indicada aqui." },
  { id: "psumg_gerado26_056", banca: "PSU-MG", cycle: "Ciclo Clínico", subject: "Endocrinologia", text: "Homem de 48 anos, obeso, com poliúria e polidipsia, glicemia de jejum de 195mg/dL em duas ocasiões. Assinale a alternativa CORRETA sobre o diagnóstico:", options: ["Pode ser confirmado por glicemia de jejum igual ou superior a 126mg/dL em duas ocasiões distintas", "Exige obrigatoriamente teste oral de tolerância à glicose em todos os casos", "Só pode ser diagnosticado na presença de cetoacidose diabética associada", "Depende exclusivamente da presença de anticorpos anti-ilhota positivos"], correctIndex: 0, explanation: "O diagnóstico de diabetes mellitus pode ser confirmado por glicemia de jejum igual ou superior a 126mg/dL em duas ocasiões distintas. O TOTG não é obrigatório em todos os casos; a cetoacidose não é pré-requisito diagnóstico do tipo 2; anticorpos anti-ilhota são marcadores do tipo 1, não do tipo 2." },
  { id: "psumg_gerado26_057", banca: "PSU-MG", cycle: "Ciclo Clínico", subject: "Endocrinologia", text: "Homem de 54 anos, formigamento em mãos e pés, fraqueza generalizada, tireoidectomia total há 3 semanas por bócio multinodular. Sinal de Trousseau positivo. Cálcio total 7,1mg/dL; fósforo 5,6mg/dL. Assinale a alternativa que apresenta uma complicação que NÃO ocorre devido ao distúrbio metabólico apresentado:", options: ["Síndrome rígido-acinética", "Laringoespasmo", "Insuficiência cardíaca", "Osteoporose"], correctIndex: 0, explanation: "A hipocalcemia pós-tireoidectomia pode causar laringoespasmo, insuficiência cardíaca e, cronicamente, alterações ósseas, mas a síndrome rígido-acinética não é complicação característica desse distúrbio, sendo mais associada a calcificações de núcleos da base em hipoparatireoidismo crônico grave de longa data, não ao quadro agudo descrito." },
  { id: "psumg_gerado26_058", banca: "PSU-MG", cycle: "Ciclo Clínico", subject: "Cardiologia", text: "Homem de 64 anos, dor torácica típica em repouso, ECG com supradesnivelamento de ST em parede anterior (V1-V4). Assinale a conduta imediata prioritária:", options: ["Reperfusão coronariana urgente, por angioplastia primária ou trombólise", "Teste ergométrico imediato para confirmação diagnóstica", "Alta hospitalar com anti-inflamatório", "Ressonância cardíaca eletiva em 30 dias"], correctIndex: 0, explanation: "Supradesnivelamento de ST com dor torácica típica caracteriza infarto agudo do miocárdio com supra de ST, exigindo reperfusão urgente. Teste ergométrico é contraindicado na fase aguda; alta com anti-inflamatório ignora uma emergência cardiovascular; ressonância eletiva atrasa o tratamento tempo-dependente." },
  { id: "psumg_gerado26_059", banca: "PSU-MG", cycle: "Ciclo Clínico", subject: "Cardiologia", text: "Mulher de 72 anos, dispneia aos pequenos esforços, edema de membros inferiores, terceira bulha audível, fração de ejeção 32%. Assinale a classe medicamentosa a ser incluída no tratamento de base:", options: ["Inibidor da enzima conversora de angiotensina associado a betabloqueador", "Apenas diurético de alça, sem qualquer outra classe medicamentosa", "Bloqueador de canal de cálcio di-hidropiridínico como base do tratamento", "Anti-inflamatório não esteroidal para controle do edema"], correctIndex: 0, explanation: "O tratamento de base da insuficiência cardíaca com fração de ejeção reduzida inclui inibidor da enzima conversora de angiotensina associado a betabloqueador. Diurético isolado trata apenas sintomas congestivos; bloqueador de canal de cálcio di-hidropiridínico não tem benefício prognóstico estabelecido; anti-inflamatório é contraindicado por piorar a retenção hidrossalina." },
  { id: "psumg_gerado26_060", banca: "PSU-MG", cycle: "Ciclo Clínico", subject: "Cardiologia", text: "Homem de 58 anos, palpitações, ECG com ritmo irregularmente irregular, ausência de ondas P, resposta ventricular de 128bpm. CHA2DS2-VASc de 3. Assinale a conduta MAIS ADEQUADA:", options: ["Anticoagulação oral, dado o escore de risco tromboembólico elevado", "Nenhuma anticoagulação, dado que a frequência cardíaca está controlada", "Cardioversão elétrica imediata, sem qualquer avaliação do risco tromboembólico prévio", "Apenas controle de frequência, sem qualquer avaliação de anticoagulação"], correctIndex: 0, explanation: "CHA2DS2-VASc de 3 indica risco tromboembólico significativo, justificando anticoagulação oral. A frequência controlada não elimina o risco tromboembólico da fibrilação atrial; cardioversão sem avaliação do risco tromboembólico e sem anticoagulação prévia adequada expõe a risco de embolização; controle de frequência isolado sem avaliar anticoagulação ignora um componente essencial do manejo." },
  { id: "psumg_gerado26_061", banca: "PSU-MG", cycle: "Ciclo Clínico", subject: "Ética Médica", text: "Em relação ao sigilo profissional médico, assinale a alternativa CORRETA:", options: ["Pode ser quebrado por justa causa, como risco iminente à vida de terceiros, respeitados os limites legais", "Pode ser quebrado diante de qualquer solicitação de autoridade, sem base legal específica", "Pode ser quebrado por pedido informal de familiares, sem qualquer outro critério", "Nunca pode ser quebrado, em nenhuma circunstância prevista em lei"], correctIndex: 0, explanation: "O sigilo médico pode ser quebrado por justa causa, como risco iminente à vida de terceiros, respeitados os limites legais. Quebrar o sigilo diante de qualquer solicitação de autoridade sem base legal específica não é eticamente correto; pedido informal de familiares não configura justa causa; afirmar que nunca pode ser quebrado ignora as exceções legalmente previstas." },
  { id: "psumg_gerado26_062", banca: "PSU-MG", cycle: "Ciclo Clínico", subject: "Ética Médica", text: "Em relação às diretivas antecipadas de vontade, assinale a alternativa CORRETA:", options: ["Permitem que o paciente registre suas preferências para tratamentos futuros, a serem respeitadas caso perca a capacidade de decisão", "Têm validade apenas para o procedimento específico realizado no momento de sua assinatura", "Substituem completamente a necessidade de qualquer consentimento informado futuro", "Só podem ser elaboradas por pacientes já em estado terminal confirmado"], correctIndex: 0, explanation: "As diretivas antecipadas permitem que o paciente registre preferências para tratamentos futuros, respeitadas caso perca a capacidade de decisão. Diferem do consentimento informado padrão, que vale para um procedimento específico no momento presente; não substituem toda necessidade de consentimento futuro; podem ser elaboradas por qualquer pessoa capaz, não apenas por pacientes já terminais." },
  { id: "psumg_gerado26_063", banca: "PSU-MG", cycle: "Ciclo Clínico", subject: "Ética Médica", text: "Adolescente de 15 anos, sexualmente ativa, procura consulta ginecológica sem os pais. Assinale a conduta ética ADEQUADA:", options: ["Respeitar o sigilo e a autonomia da adolescente, exceto em situações de risco grave previstas em lei", "Comunicar imediatamente os pais antes de qualquer atendimento", "Recusar o atendimento até que a adolescente venha acompanhada de um responsável legal", "Informar que o sigilo médico não se aplica a adolescentes em nenhuma circunstância"], correctIndex: 0, explanation: "Adolescentes têm direito ao sigilo e à autonomia crescente sobre sua saúde, com quebra de sigilo reservada a situações de risco grave previstas em lei. Comunicar os pais obrigatoriamente antes do atendimento pode afastar a adolescente do cuidado necessário; recusar o atendimento sem acompanhante prejudica a saúde da paciente; afirmar que o sigilo nunca se aplica a adolescentes contraria seus direitos reconhecidos." },
  { id: "psumg_gerado26_064", banca: "PSU-MG", cycle: "Ciclo Clínico", subject: "Nefrologia", text: "Homem de 46 anos, edema periorbitário e de membros inferiores, proteinúria de 5,2g/24h, hipoalbuminemia e hiperlipidemia, sem hematúria significativa. Assinale o diagnóstico sindrômico e a principal complicação trombótica associada:", options: ["Síndrome nefrótica; trombose de veia renal", "Síndrome nefrítica; glomerulonefrite rapidamente progressiva", "Insuficiência renal aguda pré-renal; necrose tubular aguda", "Síndrome hemolítico-urêmica; trombocitopenia isolada"], correctIndex: 0, explanation: "Proteinúria maciça, hipoalbuminemia, edema e hiperlipidemia caracterizam síndrome nefrótica, cuja complicação trombótica clássica é a trombose de veia renal. A síndrome nefrítica cursa com hematúria e hipertensão proeminentes; a insuficiência renal pré-renal não explica a proteinúria maciça; a síndrome hemolítico-urêmica cursa com anemia hemolítica microangiopática." },
  { id: "psumg_gerado26_065", banca: "PSU-MG", cycle: "Ciclo Clínico", subject: "Nefrologia", text: "Homem de 63 anos, hemodiálise crônica, ECG pré-diálise com ondas T apiculadas e QRS alargado, potássio sérico 7,4mEq/L. Assinale a conduta imediata prioritária:", options: ["Gluconato de cálcio intravenoso, seguido de medidas para reduzir o potássio sérico", "Apenas aumentar a dose de resina de troca iônica oral, sem qualquer medida imediata", "Aguardar a próxima sessão de diálise agendada, sem qualquer intervenção imediata", "Reposição de potássio oral, para investigar pseudo-hipercalemia"], correctIndex: 0, explanation: "Hipercalemia grave com alterações eletrocardiográficas exige gluconato de cálcio intravenoso imediato para estabilizar a membrana miocárdica, seguido de medidas para reduzir o potássio. Resina oral tem início de ação lento, insuficiente diante de alterações eletrocardiográficas já presentes; aguardar a próxima diálise é perigoso; repor potássio pioraria ainda mais o quadro." },
  { id: "psumg_gerado26_066", banca: "PSU-MG", cycle: "Ciclo Clínico", subject: "Nefrologia", text: "Mulher de 34 anos, infecção urinária de repetição, cólica renal recorrente, ultrassonografia com múltiplos cistos renais bilaterais e história familiar de doença renal similar em padrão autossômico dominante. Assinale uma complicação extrarrenal associada:", options: ["Aneurisma cerebral (de artérias do polígono de Willis)", "Retinose pigmentar como achado obrigatório em todos os casos", "Fibrose hepática congênita como achado predominante nessa faixa etária", "Ausência completa de qualquer risco de complicação extrarrenal"], correctIndex: 0, explanation: "A doença renal policística autossômica dominante associa-se a maior risco de aneurismas cerebrais no polígono de Willis. Retinose pigmentar relaciona-se à nefronoftise juvenil (síndrome de Senior-Løken), não sendo achado obrigatório aqui; fibrose hepática congênita é mais proeminente na forma autossômica recessiva, manifestada na infância; há sim risco real de complicação extrarrenal (aneurisma), não ausência completa desse risco." },
  { id: "psumg_gerado26_067", banca: "PSU-MG", cycle: "Ciclo Clínico", subject: "Geriatria", text: "Mulher de 82 anos, queda da própria altura, dor intensa em quadril direito, encurtamento e rotação externa do membro, radiografia confirmando fratura do colo do fêmur. Assinale a alternativa CORRETA sobre a conduta:", options: ["O tratamento cirúrgico precoce é preferível ao conservador, reduzindo complicações do imobilismo prolongado", "O tratamento conservador com repouso prolongado no leito é a conduta padrão-ouro", "A cirurgia deve ser postergada por, no mínimo, 30 dias em todos os casos", "A fratura do colo do fêmur em idosos não se associa a aumento de mortalidade"], correctIndex: 0, explanation: "Em idosos com fratura de colo de fêmur, o tratamento cirúrgico precoce é preferível ao conservador, reduzindo complicações graves do imobilismo prolongado. O tratamento conservador não é o padrão-ouro; postergar a cirurgia por 30 dias contraria a recomendação de intervenção precoce; essa fratura está associada a aumento significativo de mortalidade em idosos." },
  { id: "psumg_gerado26_068", banca: "PSU-MG", cycle: "Ciclo Clínico", subject: "Geriatria", text: "Homem de 84 anos, com perda de memória, dificuldade de concentração, insônia com despertares noturnos, sonolência diurna. Mini-exame do estado mental com pontuação baixa para a escolaridade. Vitamina B12 normal; TSH 9,2mcUI/mL; T4 livre baixo. Assinale a conduta inicial INADEQUADA em relação ao manejo das queixas cognitivas:", options: ["Prescrever inibidor da colinesterase antes de corrigir o hipotireoidismo identificado", "Prescrever levotiroxina para corrigir o hipotireoidismo identificado", "Solicitar polissonografia para investigar o distúrbio do sono relatado", "Reavaliar a cognição após correção do hipotireoidismo e do sono"], correctIndex: 0, explanation: "Prescrever inibidor da colinesterase antes de corrigir causas reversíveis identificadas (hipotireoidismo, distúrbio do sono) é conduta inadequada, pois essas causas devem ser tratadas e reavaliadas antes de se considerar demência estabelecida. Prescrever levotiroxina para o hipotireoidismo identificado é adequado; solicitar polissonografia para investigar o distúrbio do sono relatado é adequado; reavaliar a cognição após corrigir essas causas reversíveis é a conduta correta antes de rotular como demência irreversível." },
  { id: "psumg_gerado26_069", banca: "PSU-MG", cycle: "Ciclo Clínico", subject: "Reumatologia", text: "Homem de 58 anos, dor, edema e calor na 1ª articulação metatarsofalangeana direita há 2 dias, sem febre, uso de hidroclorotiazida. Ácido úrico 8,9mg/dL. Assinale a conduta MAIS ADEQUADA:", options: ["Anti-inflamatório não esteroidal ou colchicina para a crise aguda", "Iniciar alopurinol durante a crise aguda, sem tratamento sintomático prévio", "Suspender hidroclorotiazida como única conduta, sem tratamento da crise aguda", "Artrocentese obrigatória em todos os casos antes de qualquer tratamento sintomático"], correctIndex: 0, explanation: "A crise aguda de gota é tratada com anti-inflamatório não esteroidal ou colchicina, evitando iniciar hipouricemiante durante a crise, o que pode prolongá-la. Iniciar alopurinol na crise aguda pode agravar e prolongar a inflamação; suspender a hidroclorotiazida isoladamente, sem tratar a crise aguda, não trata os sintomas atuais; artrocentese pode ser considerada diagnosticamente, mas não é obrigatória em todos os casos clinicamente típicos antes do tratamento sintomático." },
  { id: "psumg_gerado26_070", banca: "PSU-MG", cycle: "Ciclo Clínico", subject: "Reumatologia", text: "Mulher de 26 anos, eritema malar poupando sulco nasolabial, fotossensibilidade, artrite não erosiva de pequenas articulações, proteinúria e FAN positivo em altos títulos, anti-DNA de dupla hélice positivo. Assinale o diagnóstico MAIS PROVÁVEL:", options: ["Lúpus eritematoso sistêmico", "Dermatomiosite", "Esclerose sistêmica", "Artrite reumatoide"], correctIndex: 0, explanation: "Eritema malar poupando sulco nasolabial, fotossensibilidade, artrite não erosiva, proteinúria e anti-DNA de dupla hélice positivo confirmam lúpus eritematoso sistêmico. A dermatomiosite cursa com heliotropo e pápulas de Gottron; a esclerose sistêmica cursa com espessamento cutâneo; a artrite reumatoide cursa com artrite erosiva simétrica, sem esse perfil sorológico." },
  { id: "psumg_gerado26_071", banca: "PSU-MG", cycle: "Ciclo Clínico", subject: "Psiquiatria", text: "Homem de 27 anos, humor eufórico há 8 dias, redução da necessidade de sono, fala acelerada, grandiosidade, envolvimento em atividades de risco financeiro, sem sintomas psicóticos. Assinale o diagnóstico e a classe medicamentosa de PRIMEIRA LINHA para o episódio agudo:", options: ["Episódio maníaco (transtorno bipolar tipo I); estabilizador de humor ou antipsicótico atípico", "Transtorno depressivo maior; inibidor seletivo da recaptação de serotonina isoladamente", "Esquizofrenia; antipsicótico típico em altas doses isoladamente", "Transtorno de ansiedade generalizada; benzodiazepínico como tratamento definitivo"], correctIndex: 0, explanation: "Humor eufórico, redução da necessidade de sono, grandiosidade e comportamento de risco caracterizam episódio maníaco, tratado com estabilizador de humor ou antipsicótico atípico. Transtorno depressivo maior cursaria com humor deprimido, não eufórico; esquizofrenia exigiria sintomas psicóticos proeminentes, ausentes no quadro; transtorno de ansiedade generalizada cursa com preocupação excessiva, não euforia e grandiosidade." },
  { id: "psumg_gerado26_072", banca: "PSU-MG", cycle: "Ciclo Clínico", subject: "Neurologia", text: "Mulher de 30 anos, episódios recorrentes de perda visual unilateral, parestesias e fraqueza em membros, ressonância evidenciando lesões desmielinizantes disseminadas no espaço e no tempo. Assinale o diagnóstico MAIS PROVÁVEL:", options: ["Esclerose múltipla", "Acidente vascular cerebral de repetição", "Miastenia gravis", "Síndrome de Guillain-Barré"], correctIndex: 0, explanation: "Lesões desmielinizantes disseminadas no espaço e no tempo são o critério diagnóstico central da esclerose múltipla. AVC de repetição teria lesões vasculares; miastenia gravis não apresenta lesões de substância branca; Guillain-Barré cursa com fraqueza ascendente aguda e arreflexia, sem esse padrão de lesões na ressonância." },
  { id: "psumg_gerado26_073", banca: "PSU-MG", cycle: "Ciclo Clínico", subject: "Medicina do Trabalho", text: "Trabalhador de 45 anos, exposto a ruído ocupacional intenso por 15 anos sem proteção auditiva adequada, audiometria evidenciando perda auditiva neurossensorial bilateral com entalhe em 4.000Hz. Assinale a alternativa CORRETA sobre a conduta:", options: ["Caracterizar a perda auditiva induzida por ruído ocupacional (PAIRO) e afastar o trabalhador da exposição contínua ao ruído sem proteção adequada", "Considerar a perda auditiva exclusivamente relacionada ao envelhecimento natural, sem relação ocupacional", "Indicar apenas cirurgia otológica corretiva, sem qualquer medida de afastamento do ruído", "Não notificar o caso, por se tratar de doença crônica sem nexo ocupacional definido"], correctIndex: 0, explanation: "O entalhe em 4.000Hz na audiometria de trabalhador exposto a ruído ocupacional intenso é achado característico da perda auditiva induzida por ruído ocupacional, exigindo afastamento da exposição contínua sem proteção adequada e notificação do caso. Atribuir exclusivamente ao envelhecimento ignora o nexo ocupacional evidenciado pelo padrão audiométrico e história de exposição; cirurgia otológica não reverte a perda neurossensorial já estabelecida; não notificar contraria a obrigatoriedade de notificação de doenças relacionadas ao trabalho." },
  { id: "psumg_gerado26_074", banca: "PSU-MG", cycle: "Ciclo Clínico", subject: "Cirurgia Geral", text: "Mulher de 40 anos, com abaulamento inguinal direito conhecido há anos, procura atendimento por dor intensa e súbita na região, associada a náuseas e impossibilidade de redução manual da massa, antes redutível. Assinale a alternativa CORRETA sobre a conduta:", options: ["Correção cirúrgica de urgência, pela suspeita de encarceramento com risco de estrangulamento", "Tentativa vigorosa e repetida de redução manual, independente do tempo de evolução da dor", "Alta com anti-inflamatório e retorno ambulatorial eletivo em algumas semanas", "Observação domiciliar até que a massa reduza espontaneamente"], correctIndex: 0, explanation: "Hérnia previamente redutível que se torna irredutível, dolorosa e associada a náuseas sugere encarceramento com risco de estrangulamento, exigindo correção cirúrgica de urgência. Tentativas vigorosas e repetidas de redução manual podem causar redução em massa de alça já isquêmica, sendo perigosas; alta com anti-inflamatório ignora uma emergência cirúrgica potencial; observação domiciliar aguardando redução espontânea arrisca necrose intestinal." },
  { id: "psumg_gerado26_075", banca: "PSU-MG", cycle: "Ciclo Clínico", subject: "Ginecologia e Obstetrícia", text: "Mulher de 36 anos, sangramento uterino aumentado e dismenorreia progressiva, útero aumentado de volume com contornos irregulares, ultrassonografia com múltiplos nódulos miometriais. Assinale o diagnóstico MAIS PROVÁVEL:", options: ["Leiomiomatose uterina (miomas)", "Adenomiose isolada, sem miomas associados", "Câncer de endométrio em estágio avançado", "Gestação ectópica"], correctIndex: 0, explanation: "Útero de contornos irregulares com múltiplos nódulos miometriais é o quadro clássico da miomatose uterina. A adenomiose isolada cursa com útero globoso aumentado difusamente, sem nódulos bem definidos; o câncer de endométrio cursaria com espessamento endometrial em mulher tipicamente pós-menopausa; a gestação ectópica não explica esses nódulos miometriais." },
  { id: "psumg_gerado26_076", banca: "PSU-MG", cycle: "Ciclo Clínico", subject: "Ginecologia e Obstetrícia", text: "Gestante de 39 semanas, em trabalho de parto, parada da progressão por 2 horas apesar de contrações adequadas, apresentação cefálica insinuada e dilatação total. Assinale a hipótese MAIS PROVÁVEL e a conduta:", options: ["Desproporção cefalopélvica ou parada secundária da descida; considerar parto instrumental ou cesariana", "Trabalho de parto normal em progressão fisiológica; apenas aguardar sem reavaliação", "Rotura uterina; observação clínica isolada, sem qualquer intervenção", "Sofrimento fetal agudo isolado sem relação com a progressão; apenas analgesia"], correctIndex: 0, explanation: "Parada da progressão apesar de contrações adequadas, com dilatação total e apresentação insinuada, sugere desproporção cefalopélvica ou parada secundária da descida, exigindo avaliação para parto instrumental ou cesariana. Não é progressão fisiológica normal, pois há parada documentada; rotura uterina teria sinais mais agudos e graves; sofrimento fetal agudo isolado não descreve o caso, que é de parada mecânica da progressão." },
  { id: "psumg_gerado26_077", banca: "PSU-MG", cycle: "Ciclo Clínico", subject: "Ginecologia e Obstetrícia", text: "Gestante de 29 semanas, sem intercorrências prévias, na consulta de rotina. Assinale a alternativa CORRETA sobre o rastreamento de diabetes mellitus gestacional:", options: ["O teste oral de tolerância à glicose com 75g é recomendado entre 24 e 28 semanas para gestantes sem diagnóstico prévio", "O rastreamento não é recomendado em nenhuma gestante sem fatores de risco prévios", "A glicemia de jejum isolada no primeiro trimestre exclui definitivamente o diagnóstico em qualquer momento da gestação", "O diagnóstico só pode ser confirmado no puerpério, nunca durante a gestação"], correctIndex: 0, explanation: "O teste oral de tolerância à glicose com 75g entre 24 e 28 semanas é o método recomendado para rastreamento de diabetes gestacional. Não rastrear nenhuma gestante contraria as recomendações vigentes; a glicemia de jejum no primeiro trimestre não substitui o rastreamento entre 24-28 semanas; o diagnóstico pode e deve ser feito durante a gestação, não apenas no puerpério." },
  { id: "psumg_gerado26_078", banca: "PSU-MG", cycle: "Ciclo Clínico", subject: "Ginecologia e Obstetrícia", text: "Mulher de 30 anos, puérpera imediata, sangramento vaginal importante e útero hipotônico à palpação após dequitação completa. Assinale a primeira conduta:", options: ["Massagem uterina bimanual e ocitocina", "Histerectomia imediata", "Apenas observação", "Curetagem imediata, sem avaliar o tônus uterino"], correctIndex: 0, explanation: "Atonia uterina, causa mais comum de hemorragia pós-parto, é tratada inicialmente com massagem bimanual e ocitocina. Histerectomia imediata é medida de exceção para casos refratários; observação isolada é perigosa diante de sangramento ativo; curetagem sem avaliar o tônus ignora a causa mais provável." },
  { id: "psumg_gerado26_079", banca: "PSU-MG", cycle: "Ciclo Clínico", subject: "Pediatria", text: "Lactente de 5 meses, vômitos em jato pós-prandiais, oliva palpável em epigástrio, alcalose metabólica hipoclorêmica. Assinale a conduta antes da cirurgia:", options: ["Correção do distúrbio hidroeletrolítico", "Cirurgia imediata sem correção prévia", "Antibioticoterapia isolada", "Apenas dieta espessada, sem cirurgia"], correctIndex: 0, explanation: "Na estenose hipertrófica do piloro, o distúrbio hidroeletrolítico deve ser corrigido antes da piloromiotomia. Cirurgia imediata sem correção prévia aumenta o risco anestésico-metabólico; antibioticoterapia não trata a obstrução mecânica pilórica; dieta espessada isolada não resolve a obstrução anatômica." },
  { id: "psumg_gerado26_080", banca: "PSU-MG", cycle: "Ciclo Clínico", subject: "Pediatria", text: "Recém-nascido, icterícia nas primeiras 24 horas de vida, Coombs direto positivo, mãe Rh negativo sensibilizada. Assinale a conduta MAIS PROVÁVEL a ser necessária:", options: ["Fototerapia intensiva e possível exsanguineotransfusão conforme evolução", "Apenas observação clínica, sem qualquer tratamento", "Suspensão do aleitamento materno como única conduta", "Antibioticoterapia empírica isolada"], correctIndex: 0, explanation: "Icterícia precoce por doença hemolítica perinatal exige fototerapia intensiva, com exsanguineotransfusão reservada a casos graves. Observação isolada é perigosa diante de icterícia precoce por hemólise; suspender o aleitamento materno não trata a causa hemolítica; antibioticoterapia empírica não trata a hemólise." },
  { id: "psumg_gerado26_081", banca: "PSU-MG", cycle: "Ciclo Clínico", subject: "Ginecologia e Obstetrícia", text: "Mulher de 42 anos, na pós-menopausa, sangramento vaginal há 3 semanas, ultrassonografia com espessamento endometrial de 13mm. Assinale a conduta diagnóstica MAIS ADEQUADA:", options: ["Biópsia endometrial (por histeroscopia, curetagem ou outro método adequado)", "Observação clínica isolada, sem qualquer investigação adicional", "Histerectomia imediata, sem biópsia prévia", "Terapia hormonal isolada, sem investigação da causa do sangramento"], correctIndex: 0, explanation: "Sangramento pós-menopausa com espessamento endometrial exige biópsia para investigação histológica, excluindo hiperplasia atípica ou carcinoma. Observação isolada atrasa perigosamente o diagnóstico; histerectomia sem biópsia prévia é desproporcional; terapia hormonal isolada não investiga a causa nem exclui malignidade." },
  { id: "psumg_gerado26_082", banca: "PSU-MG", cycle: "Ciclo Clínico", subject: "Cirurgia Geral", text: "Homem de 62 anos, massa cervical anterior palpável, ultrassonografia com nódulo tireoidiano de 2,2cm, hipoecoico, com microcalcificações e margens irregulares. Assinale a conduta MAIS ADEQUADA:", options: ["Punção aspirativa por agulha fina guiada por ultrassonografia", "Tireoidectomia total imediata, sem qualquer confirmação citológica prévia", "Observação clínica isolada por 24 meses, sem qualquer investigação adicional", "Cintilografia tireoidiana como único exame necessário, sem punção"], correctIndex: 0, explanation: "Nódulo com características ultrassonográficas de alto risco tem indicação de punção aspirativa por agulha fina para definir a conduta. Tireoidectomia sem confirmação citológica é desproporcional; observação isolada por 24 meses ignora características de alto risco; cintilografia não substitui a punção diante dessas características suspeitas." },
  { id: "psumg_gerado26_083", banca: "PSU-MG", cycle: "Ciclo Clínico", subject: "Pediatria", text: "Menino de 3 anos, dor articular e claudicação em perna direita há 24 horas, sem febre, quadro gripal autolimitado há 1 semana, posição antálgica do joelho e rotação externa do membro. Assinale a abordagem MAIS ADEQUADA:", options: ["Ultrassonografia de quadril para avaliar sinovite transitória, com manejo sintomático e observação", "Antibioticoterapia empírica de amplo espectro imediata, sem qualquer investigação prévia", "Punção articular de urgência, independente da ausência de febre e sinais de toxemia", "Ressonância magnética de coluna lombar como primeiro exame, sem avaliação do quadril"], correctIndex: 0, explanation: "Claudicação após quadro viral, sem febre ou toxemia, é compatível com sinovite transitória do quadril, investigada com ultrassonografia e manejada com sintomáticos. Antibioticoterapia empírica imediata sem investigação é desproporcional na ausência de sinais de infecção; punção articular de urgência não é indicada sem sinais de toxemia; ressonância de coluna lombar não é o exame direcionado para esse quadro de quadril." },
  { id: "psumg_gerado26_084", banca: "PSU-MG", cycle: "Ciclo Clínico", subject: "Infectologia", text: "Homem de 30 anos, contato sexual desprotegido há 3 dias com parceiro com sorologia positiva para HIV conhecida. Assinale a conduta MAIS ADEQUADA:", options: ["Iniciar profilaxia pós-exposição (PEP) com esquema antirretroviral o mais rápido possível, idealmente em até 72 horas", "Aguardar sorologia do paciente em 30 dias antes de iniciar qualquer medicação", "Iniciar apenas aconselhamento, sem qualquer medicação antirretroviral", "Iniciar profilaxia pré-exposição (PrEP) contínua, ao invés de PEP, para esse evento pontual"], correctIndex: 0, explanation: "Exposição sexual de risco a parceiro HIV positivo exige início da profilaxia pós-exposição o mais rápido possível, idealmente em até 72 horas, para reduzir o risco de infecção. Aguardar sorologia em 30 dias antes de medicar perde a janela de eficácia da profilaxia; apenas aconselhamento sem medicação não oferece a proteção farmacológica necessária diante de exposição de risco recente; a PrEP contínua é indicada para exposição continuada de risco, não para um evento pontual já ocorrido, que exige PEP." },
  { id: "psumg_gerado26_085", banca: "PSU-MG", cycle: "Ciclo Clínico", subject: "Cardiologia", text: "Mulher de 68 anos, síncope aos esforços, sopro sistólico rude em foco aórtico irradiado para carótidas, ecocardiograma com área valvar aórtica de 0,7cm². Assinale a conduta definitiva:", options: ["Troca valvar aórtica, cirúrgica ou por via transcateter conforme risco", "Tratamento clínico exclusivo, sem qualquer intervenção sobre a válvula", "Apenas seguimento ecocardiográfico anual, sem qualquer intervenção", "Betabloqueador em altas doses como única conduta"], correctIndex: 0, explanation: "Estenose aórtica grave sintomática tem indicação de troca valvar, cirúrgica ou transcateter conforme o risco do paciente. Tratamento clínico exclusivo não modifica a obstrução mecânica nem reduz o risco de morte súbita; seguimento isolado é apropriado apenas para estenose assintomática; betabloqueador em altas doses pode ser deletério nessa condição." },
  { id: "psumg_gerado26_086", banca: "PSU-MG", cycle: "Ciclo Clínico", subject: "Pediatria", text: "Recém-nascido, filho de mãe diabética com controle glicêmico inadequado, tremores e sudorese nas primeiras horas de vida, glicemia capilar 24mg/dL. Assinale a conduta imediata:", options: ["Oferecer glicose (oral ou endovenosa conforme gravidade) e reavaliar a glicemia", "Observação clínica isolada, sem qualquer intervenção", "Restrição total de qualquer oferta láctea até estabilização espontânea", "Administração isolada de insulina, para evitar hiperglicemia de rebote"], correctIndex: 0, explanation: "Hipoglicemia sintomática no filho de mãe diabética exige correção imediata com oferta de glicose, com reavaliação da glicemia. Observação isolada sem correção é perigosa; restringir a oferta láctea pioraria a hipoglicemia; insulina é contraindicada nesse contexto de hipoglicemia." },
  { id: "psumg_gerado26_087", banca: "PSU-MG", cycle: "Ciclo Clínico", subject: "Saúde Coletiva", text: "Em relação aos princípios doutrinários do SUS, assinale a alternativa CORRETA sobre a equidade:", options: ["Busca reduzir desigualdades, ofertando mais recursos e atenção a quem mais necessita", "Garante tratamento estritamente igual a todos, independente das diferenças de necessidade", "Restringe o acesso aos serviços de saúde a grupos populacionais específicos", "Centraliza toda a decisão sanitária exclusivamente no nível federal"], correctIndex: 0, explanation: "A equidade busca reduzir desigualdades, ofertando mais atenção a quem mais necessita. Garantir tratamento estritamente igual a todos, ignorando diferenças de necessidade, não corresponde ao conceito de equidade; a equidade não implica restrição de acesso a grupos específicos; a organização do SUS é descentralizada, não centralizada exclusivamente no nível federal." },
  { id: "psumg_gerado26_088", banca: "PSU-MG", cycle: "Ciclo Clínico", subject: "Cirurgia Geral", text: "Mulher de 58 anos, massa palpável em quadrante superior externo da mama esquerda, mamografia com lesão espiculada BI-RADS 5. Assinale o próximo passo MAIS ADEQUADO antes de definir a estratégia terapêutica:", options: ["Biópsia percutânea (core biopsy) para confirmação histológica", "Mastectomia radical imediata, sem confirmação histológica prévia", "Observação clínica com nova mamografia em 12 meses", "Quimioterapia empírica, sem qualquer biópsia"], correctIndex: 0, explanation: "Mesmo com alta suspeição radiológica, a biópsia percutânea é necessária para confirmação histológica antes de definir a estratégia terapêutica. Mastectomia sem confirmação histológica submeteria a paciente a cirurgia mutiladora sem diagnóstico definitivo; observação por 12 meses é inadequada diante de lesão de alta suspeição; quimioterapia empírica sem biópsia trataria uma doença ainda não confirmada." },
  { id: "psumg_gerado26_089", banca: "PSU-MG", cycle: "Ciclo Clínico", subject: "Pediatria", text: "Menina de 8 anos, púrpura palpável em membros inferiores, dor abdominal em cólica e artralgia em joelhos, sem plaquetopenia. Assinale a principal hipótese diagnóstica e o órgão a ser monitorado a médio prazo:", options: ["Púrpura de Henoch-Schönlein (vasculite por IgA); rim, pelo risco de nefrite associada", "Púrpura trombocitopênica imune; fígado, pelo risco de insuficiência hepática", "Meningococcemia; pulmão, isoladamente", "Leucemia aguda; baço, isoladamente"], correctIndex: 0, explanation: "Púrpura palpável associada a dor abdominal e artralgia, sem plaquetopenia, é típica da púrpura de Henoch-Schönlein, exigindo monitorização renal pelo risco de nefrite por IgA. A ausência de plaquetopenia afasta a púrpura trombocitopênica imune; meningococcemia cursaria com quadro toxêmico grave; leucemia aguda não é a hipótese mais compatível sem outras alterações hematológicas." },
  { id: "psumg_gerado26_090", banca: "PSU-MG", cycle: "Ciclo Clínico", subject: "Ginecologia e Obstetrícia", text: "Mulher de 24 anos, corrimento vaginal amarelo-esverdeado, prurido intenso, colo uterino com aspecto de \"morango\" ao exame especular. Assinale o agente etiológico MAIS PROVÁVEL e a conduta:", options: ["Trichomonas vaginalis; metronidazol para a paciente e o(s) parceiro(s) sexual(is)", "Candida albicans; antifúngico tópico isolado, sem tratamento do parceiro", "Gardnerella vaginalis; metronidazol, sem necessidade de tratar o parceiro", "Chlamydia trachomatis; azitromicina isolada, sem relação com o achado de colo em \"morango\""], correctIndex: 0, explanation: "O colo em aspecto de \"morango\" associado a corrimento e prurido é achado clássico de tricomoníase, tratada com metronidazol, com necessidade de tratar também o parceiro sexual. Candida causa corrimento em grumos sem esse aspecto de colo; Gardnerella não costuma causar prurido intenso nem esse aspecto de colo; clamídia não é a etiologia mais associada a esse achado específico." },
  { id: "psumg_gerado26_091", banca: "PSU-MG", cycle: "Ciclo Clínico", subject: "Cirurgia Geral", text: "Homem de 25 anos, dor testicular esquerda súbita e intensa, náuseas, testículo elevado e horizontalizado, ausência de reflexo cremastérico ipsilateral. Assinale a conduta imediata:", options: ["Exploração cirúrgica de urgência, dada a suspeita de torção testicular", "Ultrassonografia com Doppler antes de qualquer decisão, mesmo que atrase a intervenção além de 6 horas", "Antibioticoterapia empírica isolada, sem avaliação cirúrgica", "Analgesia isolada e reavaliação ambulatorial em 48 horas"], correctIndex: 0, explanation: "Dor testicular súbita intensa com testículo elevado e horizontalizado e ausência de reflexo cremastérico é quadro clássico de torção testicular, emergência urológica que exige exploração cirúrgica imediata. Aguardar ultrassonografia quando isso atrasaria a intervenção além da janela de viabilidade testicular é perigoso; antibioticoterapia isolada trataria epididimite, não a torção; analgesia isolada com reavaliação tardia arrisca perda do testículo." },
  { id: "psumg_gerado26_092", banca: "PSU-MG", cycle: "Ciclo Clínico", subject: "Pediatria", text: "Lactente de 9 meses, previamente hígido, tosse, coriza e sibilância há 2 dias, desconforto respiratório leve, primeiro episódio de sibilância, teste rápido positivo para vírus sincicial respiratório. Assinale a conduta:", options: ["Suporte com lavagem nasal, oxigenoterapia se necessário e hidratação, sem broncodilatador, corticoide ou antibiótico de rotina", "Corticoide sistêmico em dose única, indicado rotineiramente para reduzir o tempo de internação", "Antibioticoterapia empírica de rotina, dada a alta taxa de coinfecção bacteriana", "Broncodilatador inalatório de rotina e continuado em todos os casos"], correctIndex: 0, explanation: "O tratamento da bronquiolite viral aguda é essencialmente de suporte, sem benefício comprovado de broncodilatador, corticoide ou antibiótico de rotina. Corticoide sistêmico não reduz tempo de internação nessa condição; antibioticoterapia empírica não é indicada sem sinais de infecção bacteriana concomitante; broncodilatador de rotina não tem eficácia comprovada na bronquiolite." },
  { id: "psumg_gerado26_093", banca: "PSU-MG", cycle: "Ciclo Clínico", subject: "Ginecologia e Obstetrícia", text: "Mulher de 22 anos, nuligesta, ciclos menstruais irregulares, hirsutismo e acne, deseja engravidar futuramente. Assinale a alternativa CORRETA sobre o tratamento da síndrome dos ovários policísticos nesse contexto:", options: ["O manejo do estilo de vida (dieta e exercício) é recomendado como base do tratamento, independente do desejo reprodutivo futuro", "O contraceptivo hormonal combinado é a única opção terapêutica válida, mesmo com desejo reprodutivo futuro", "A metformina é contraindicada em qualquer paciente com síndrome dos ovários policísticos", "A cirurgia bariátrica é o tratamento de primeira linha independente do índice de massa corporal"], correctIndex: 0, explanation: "O manejo do estilo de vida, incluindo dieta e exercício, é recomendado como base do tratamento da síndrome dos ovários policísticos, independentemente do desejo reprodutivo futuro, melhorando resistência insulínica e sintomas. O contraceptivo combinado não é a única opção, especialmente quando há desejo reprodutivo, sendo preferíveis outras abordagens para indução de ovulação nesse contexto; a metformina não é contraindicada de forma geral, sendo inclusive utilizada em casos com resistência insulínica; a cirurgia bariátrica não é tratamento de primeira linha independente do IMC, sendo reservada a casos de obesidade grave com indicação específica." },
  { id: "psumg_gerado26_094", banca: "PSU-MG", cycle: "Ciclo Clínico", subject: "Cirurgia Geral", text: "Homem de 50 anos, ferimento penetrante abdominal por arma de fogo, instável hemodinamicamente. Assinale a conduta padrão, segundo os princípios de cirurgia de controle de danos:", options: ["Controle rápido de hemorragia e contaminação, adiando reconstruções definitivas para momento posterior", "Reconstrução anatômica completa e definitiva de todas as lesões na primeira intervenção", "Observação clínica isolada, sem intervenção cirúrgica imediata", "Anastomoses intestinais múltiplas complexas como prioridade sobre o controle hemorrágico"], correctIndex: 0, explanation: "A cirurgia de controle de danos prioriza o controle rápido de hemorragia e contaminação, adiando reconstruções definitivas para depois da estabilização fisiológica. Reconstrução completa na primeira intervenção prolonga o tempo cirúrgico e agrava a tríade letal; observação isolada é inadequada diante de instabilidade e ferimento penetrante; anastomoses complexas antes do controle hemorrágico invertem a prioridade correta." },
  { id: "psumg_gerado26_095", banca: "PSU-MG", cycle: "Ciclo Clínico", subject: "Pediatria", text: "Menino de 7 anos, enurese noturna isolada, exame físico normal. Assinale a conduta inicial:", options: ["Orientação comportamental e reasseguramento", "Desmopressina imediata sem orientação comportamental prévia", "Investigação urológica invasiva imediata", "Restrição hídrica extrema durante todo o dia"], correctIndex: 0, explanation: "Enurese isolada sem sinais de alarme é tratada inicialmente com orientação comportamental, reservando medicação para casos persistentes. Desmopressina imediata sem tentativa comportamental prévia pula uma etapa terapêutica de primeira linha; investigação urológica invasiva não é indicada na ausência de sinais de alarme; restrição hídrica extrema é inadequada e pode causar desidratação." },
  { id: "psumg_gerado26_096", banca: "PSU-MG", cycle: "Ciclo Clínico", subject: "Ginecologia e Obstetrícia", text: "Mulher de 33 anos, com dor pélvica, febre e corrimento cervical purulento, dor à mobilização do colo uterino. Assinale a conduta MAIS ADEQUADA:", options: ["Iniciar antibioticoterapia empírica de amplo espectro para doença inflamatória pélvica, cobrindo gonococo e clamídia", "Aguardar resultado de cultura antes de iniciar qualquer tratamento", "Indicar laparotomia exploradora imediata, independente da gravidade", "Iniciar apenas analgésico, sem qualquer antibioticoterapia"], correctIndex: 0, explanation: "A suspeita clínica de doença inflamatória pélvica justifica início empírico imediato de antibioticoterapia cobrindo gonococo e clamídia, sem necessidade de aguardar cultura, reduzindo o risco de sequelas. Aguardar cultura atrasa o tratamento; laparotomia é reservada a complicações como abscesso tubo-ovariano roto; analgésico isolado não trata a infecção subjacente." },
  { id: "psumg_gerado26_097", banca: "PSU-MG", cycle: "Ciclo Clínico", subject: "Cirurgia Geral", text: "Homem de 33 anos, dor abdominal difusa, febre e rigidez abdominal generalizada 3 dias após colecistectomia videolaparoscópica, tomografia evidenciando coleção líquida perihepática com bolhas de ar. Assinale a conduta MAIS ADEQUADA:", options: ["Drenagem da coleção (percutânea ou cirúrgica) associada a antibioticoterapia de amplo espectro", "Apenas antibioticoterapia oral ambulatorial, sem qualquer drenagem", "Observação clínica isolada por 7 dias, sem qualquer intervenção", "Colecistectomia de repetição, independente da causa da coleção"], correctIndex: 0, explanation: "Coleção líquida perihepática com bolhas de ar após colecistectomia sugere coleção infectada (possível lesão de via biliar ou abscesso), exigindo drenagem associada a antibioticoterapia de amplo espectro. Antibioticoterapia oral isolada é insuficiente diante de uma coleção que necessita drenagem; observação isolada por 7 dias atrasa o tratamento de um foco infeccioso abdominal; colecistectomia de repetição não é a conduta apropriada, pois a vesícula já foi removida, sendo necessário investigar e tratar a causa da coleção." },
  { id: "psumg_gerado26_098", banca: "PSU-MG", cycle: "Ciclo Clínico", subject: "Pediatria", text: "Recém-nascido, 20 dias de vida, teste do pezinho evidenciando TSH de 42mUI/L (referência até 10) com T4 total baixo, coletado com 5 dias de vida. Assinale a conduta MAIS ADEQUADA:", options: ["Iniciar levotiroxina imediatamente, sem aguardar exame confirmatório, dado o risco de dano neurológico com o atraso", "Aguardar reavaliação sorológica em 6 meses antes de iniciar qualquer tratamento", "Solicitar apenas ultrassonografia de tireoide, sem iniciar tratamento hormonal", "Orientar apenas seguimento pediátrico de rotina, sem qualquer exame ou tratamento adicional"], correctIndex: 0, explanation: "TSH elevado com T4 baixo no teste do pezinho indica hipotireoidismo congênito, exigindo início imediato de levotiroxina sem aguardar confirmação, pelo risco de dano neurológico irreversível com o atraso terapêutico. Aguardar 6 meses para reavaliação expõe a criança a um período crítico de desenvolvimento neurológico sem tratamento; ultrassonografia de tireoide pode ser realizada para investigar a etiologia, mas não deve atrasar o início do tratamento hormonal; apenas seguimento de rotina sem tratamento ignora um resultado de triagem já alterado e com risco estabelecido." },
  { id: "psumg_gerado26_099", banca: "PSU-MG", cycle: "Ciclo Clínico", subject: "Ginecologia e Obstetrícia", text: "Mulher de 29 anos, atraso menstrual de 8 semanas, útero maior que o esperado para a idade gestacional, hCG muito elevado, ultrassonografia com padrão heterogêneo intrauterino em \"flocos de neve\", sem embrião identificável. Assinale a conduta:", options: ["Esvaziamento uterino por aspiração e curetagem, com seguimento seriado de beta-hCG", "Apenas acompanhamento pré-natal de rotina, sem qualquer intervenção", "Laparotomia de urgência, independente da estabilidade hemodinâmica", "Apenas expectante, sem necessidade de esvaziamento uterino nem seguimento laboratorial"], correctIndex: 0, explanation: "Útero maior que o esperado, hCG muito elevado e padrão em \"flocos de neve\" sem embrião são característicos de mola hidatiforme completa, tratada com esvaziamento uterino e seguimento seriado de beta-hCG para detectar neoplasia trofoblástica persistente. Acompanhamento de rotina ignora um achado patológico já identificado; laparotomia de urgência não é indicada nesse contexto sem sinais de abdome agudo; conduta apenas expectante sem seguimento laboratorial arrisca não detectar neoplasia trofoblástica persistente." },
  { id: "psumg_gerado26_100", banca: "PSU-MG", cycle: "Ciclo Clínico", subject: "Cirurgia Geral", text: "Mulher de 66 anos, massa abdominal pulsátil identificada em exame de rotina, ultrassonografia confirmando aneurisma de aorta abdominal infrarrenal de 5,6cm, assintomático. Assinale a conduta MAIS ADEQUADA:", options: ["Correção cirúrgica eletiva (aberta ou endovascular)", "Acompanhamento seriado anual, sem intervenção, independente do tamanho", "Anticoagulação plena isolada, sem qualquer intervenção sobre o aneurisma", "Observação clínica exclusiva até que a paciente se torne sintomática"], correctIndex: 0, explanation: "Aneurisma acima de 5,5cm tem indicação de correção eletiva pelo risco progressivo de rotura, independentemente de sintomas. Acompanhamento seriado é apropriado para aneurismas menores, abaixo do limiar cirúrgico; anticoagulação plena não trata o risco de rotura; aguardar sintomas é perigoso, pois podem indicar rotura iminente." },
];
